        void Write_Log_File(string input)
        {
            log_file_tmp_length += input.Length;
            log_file_tmp_data += input;

            if (log_file_tmp_length > 100)
            {
                if (File.Exists(iMS_Link_log_filename) == false)
                {
                    //richTextBox1.Text += "檔案: " + iMS_Link_log_filename + " 不存在，製作一個。\n";
                    StreamWriter sw = File.CreateText(iMS_Link_log_filename);
                    sw.Write(log_file_tmp_data);
                    sw.Close();
                }
                else
                {
                    //richTextBox1.Text += "檔案: " + iMS_Link_log_filename + " 存在, 開啟，並接續寫入資料。\n";
                    StreamWriter sw = File.AppendText(iMS_Link_log_filename);
                    sw.Write(log_file_tmp_data);
                    sw.Close();
                }
                log_file_tmp_length = 0;
                log_file_tmp_data = "";
            }
        }

        public struct RGB
        {
            private byte _r;
            private byte _g;
            private byte _b;

            public RGB(byte r, byte g, byte b)
            {
                this._r = r;
                this._g = g;
                this._b = b;
            }

            public byte R
            {
                get { return this._r; }
                set { this._r = value; }
            }

            public byte G
            {
                get { return this._g; }
                set { this._g = value; }
            }

            public byte B
            {
                get { return this._b; }
                set { this._b = value; }
            }

            public bool Equals(RGB rgb)
            {
                return (this.R == rgb.R) && (this.G == rgb.G) && (this.B == rgb.B);
            }
        }

        public struct YUV
        {
            private double _y;
            private double _u;
            private double _v;

            public YUV(double y, double u, double v)
            {
                this._y = y;
                this._u = u;
                this._v = v;
            }

            public double Y
            {
                get { return this._y; }
                set { this._y = value; }
            }

            public double U
            {
                get { return this._u; }
                set { this._u = value; }
            }

            public double V
            {
                get { return this._v; }
                set { this._v = value; }
            }

            public bool Equals(YUV yuv)
            {
                return (this.Y == yuv.Y) && (this.U == yuv.U) && (this.V == yuv.V);
            }
        }

        public static YUV RGBToYUV(RGB rgb)
        {
            double y = rgb.R * .299000 + rgb.G * .587000 + rgb.B * .114000;
            double u = rgb.R * -.168736 + rgb.G * -.331264 + rgb.B * .500000 + 128;
            double v = rgb.R * .500000 + rgb.G * -.418688 + rgb.B * -.081312 + 128;

            return new YUV(y, u, v);
        }

        /*
            cmx00 = cmx00d;
            cmx01 = cmx01d;
            cmx02 = cmx02d;
            cmx10 = cmx10d;
            cmx11 = cmx11d;
            cmx12 = cmx12d;
            cmx20 = cmx20d;
            cmx21 = cmx21d;
            cmx22 = cmx22d;
        */
        public YUV RGBToYUV_new(RGB rgb)
        {
            double y = rgb.R * cmx00 + rgb.G * cmx01 + rgb.B * cmx02;
            double u = rgb.R * cmx10 + rgb.G * cmx11 + rgb.B * cmx12 + 128;
            double v = rgb.R * cmx20 + rgb.G * cmx21 + rgb.B * cmx22 + 128;

            return new YUV(y, u, v);
        }

        /* old
        public static RGB YUVToRGB(YUV yuv)
        {
            byte r = (byte)(yuv.Y + 1.4075 * (yuv.V - 128));
            byte g = (byte)(yuv.Y - 0.3455 * (yuv.U - 128) - (0.7169 * (yuv.V - 128)));
            byte b = (byte)(yuv.Y + 1.7790 * (yuv.U - 128));

            return new RGB(r, g, b);
        }
        */

        public static RGB YUVToRGB(YUV yuv)
        {
            double r = yuv.Y + 1.4075 * (yuv.V - 128);
            double g = yuv.Y - 0.3455 * (yuv.U - 128) - (0.7169 * (yuv.V - 128));
            double b = yuv.Y + 1.7790 * (yuv.U - 128);
            if (r > 255)
                r = 255;
            if (g > 255)
                g = 255;
            if (b > 255)
                b = 255;
            if (r < 0)
                r = 0;
            if (g < 0)
                g = 0;
            if (b < 0)
                b = 0;

            return new RGB((byte)r, (byte)g, (byte)b);
        }

        //WM_COPYDATA消息所要求的數據結構
        public struct CopyDataStruct
        {
            public IntPtr dwData;
            public int cbData;

            [MarshalAs(UnmanagedType.LPStr)]
            public string lpData;
        }

        public const int WM_COPYDATA = 0x004A;

        //通過窗口的標題來查找窗口的句柄 
        [DllImport("User32.dll", EntryPoint = "FindWindow")]
        private static extern int FindWindow(string lpClassName, string lpWindowName);

        //在DLL庫中的發送消息函數
        [DllImport("User32.dll", EntryPoint = "SendMessage")]
        private static extern int SendMessage
            (
            int hWnd,                         // 目標窗口的句柄  
            int Msg,                          // 在這裡是WM_COPYDATA
            int wParam,                       // 第一個消息參數
            ref  CopyDataStruct lParam        // 第二個消息參數
           );

        //接收消息方法
        protected override void WndProc(ref System.Windows.Forms.Message e)
        {
            if (e.Msg == WM_COPYDATA)
            {
                CopyDataStruct cds = (CopyDataStruct)e.GetLParam(typeof(CopyDataStruct));
                richTextBox_plc.Text += "取得訊息: " + cds.lpData.ToString() + "\n";

                string message = "OKOK";
                if (cds.lpData.ToString() == "Reboot ims")
                {
                    richTextBox_plc.Text += "ims燒錄主機重開, 並回覆OK\n";
                    reset_IMS_DataWrite();
                    message = "OKOK";
                    //CopyDataStruct cds;
                    cds.dwData = (IntPtr)1; //這裡可以傳入一些自定義的數據，但只能是4字節整數      
                    cds.lpData = message;    //消息字符串
                    cds.cbData = System.Text.Encoding.Default.GetBytes(message).Length + 1;  //注意，這裡的長度是按字節來算的
                    SendMessage(FindWindow(null, "IMS"), WM_COPYDATA, 0, ref cds);       // 這裡要修改成接收窗口的標題“接收端”
                }
                else
                {
                    //richTextBox_plc.Text += "其他訊息, 不理睬\n";
                    message = "FAIL";
                    //CopyDataStruct cds;
                    cds.dwData = (IntPtr)1; //這裡可以傳入一些自定義的數據，但只能是4字節整數      
                    cds.lpData = message;    //消息字符串
                    cds.cbData = System.Text.Encoding.Default.GetBytes(message).Length + 1;  //注意，這裡的長度是按字節來算的
                    SendMessage(FindWindow(null, "IMS"), WM_COPYDATA, 0, ref cds);       // 這裡要修改成接收窗口的標題“接收端”
                }
            }
            base.WndProc(ref e);
        }

