        private void Form1_Load(object sender, EventArgs e)
        {
            if (flag_enaglb_automation == true)
            {
                flag_use_specific_ims = true;
                //自動化, 偽連上網路磁碟機
                flag_network_disk_status = true;
            }
            else
            {
                flag_use_specific_ims = false;
            }

            // 判斷是否已有程式在執行
            string proc = Process.GetCurrentProcess().ProcessName;
            Process[] processes = Process.GetProcessesByName(proc);

            //richTextBox1.Text += "ProcessName : " + proc + "\tlen = " + processes.Length.ToString() + "\n";
            if (processes.Length > 1)
            {
                MessageBox.Show("自動化作業程式 " + proc + " 已經在執行", "重複執行錯誤", MessageBoxButtons.OK, MessageBoxIcon.Error);
                Close();
            }

            if (flag_enaglb_automation == true)
            {
                richTextBox1.Text += "自動化作業程式\t";

                int operation_mode = 0;	//0: 色彩調教, 1: 資料燒錄
                if (AUTOMATION_MODE == MODE_WRITE_DATA)
                {
                    operation_mode = 1;
                    iMS_Link_log_filename = Application.StartupPath + "\\log\\iMS_Link" + DateTime.Now.ToString("yyyyMMdd") + "_WRITE_DATA.log";
                }
                else
                {
                    operation_mode = 0;
                    iMS_Link_log_filename = Application.StartupPath + "\\log\\iMS_Link" + DateTime.Now.ToString("yyyyMMdd") + "_AWB.log";
                }
                Properties.Settings.Default.operation_mode = operation_mode;

                //是否使用真的PLC, true: 真上位PLC, false: 假上位, 偽裝PLC上位來下命令
                if (AUTOMATION_USE_PLC == true)
                {
                    richTextBox1.Text += "真上位\t";
                    flag_use_real_plc = true;
                }
                else
                {
                    richTextBox1.Text += "假上位\t";
                    flag_use_real_plc = false;
                }

                Properties.Settings.Default.automation_use_plc = flag_use_real_plc;

                //是否使用真的 IMS 執行 燒錄 或 色調, true: 真下位, false: 假下位
                if (AUTOMATION_USE_IMS == true)
                {
                    richTextBox1.Text += "真下位\n";
                    flag_use_real_ims = true;
                }
                else
                {
                    richTextBox1.Text += "假下位\n";
                    flag_use_real_ims = false;
                }
                Properties.Settings.Default.automation_use_ims = flag_use_real_ims;

                //內視鏡種類 0: 胃鏡, 1: 食道鏡
                int egd_type = AUTOMATION_EGD_TYPE;
                Properties.Settings.Default.egd_type = egd_type;

                Properties.Settings.Default.Save();
            }

            Get_iMS_Link_Parameters();
            Init_iMS_Link(sender, e);

            if (flag_enaglb_automation == true)
            {
                bt_awb_test_Click(sender, e);
                timer_automation.Enabled = false;
            }
            else
            {
                timer_automation.Enabled = false;
            }
        }

        [DllImport("kernel32")]
        private static extern int GetPrivateProfileString(string sectionName, string key, string defaultValue, byte[] returnBuffer, int size, string filePath);

        /// <summary>
        /// 写入ini配置文件
        /// </summary>
        /// <param name="sectionName">要写入的section名</param>
        /// <param name="key">要写入的key，如果传入为null，整个sectionName被清除</param>
        /// <param name="value">key所对应的值，如果传入为null，此key将被清除</param>
        /// <param name="filePath">ini文件的完整路径和文件名</param>
        /// <see cref="https://msdn.microsoft.com/zh-cn/library/ms725501.aspx"/>
        /// <returns></returns>

        /// <summary>
        /// 根据key读取Value
        /// </summary>
        /// <param name="sectionName">section名称</param>
        /// <param name="key">key的名称</param>
        /// <param name="filePath">文件路径</param>
        public static string GetIniFileValue(string sectionName, string key, string filePath)
        {
            byte[] buffer = new byte[2048];
            int length = GetPrivateProfileString(sectionName, key, "", buffer, 999, filePath);
            string rs = System.Text.UTF8Encoding.Default.GetString(buffer, 0, length);
            return rs;
        }

        void Get_iMS_Link_Parameters()
        {
            if (flag_enaglb_automation == false)
            {
                return;
            }

            richTextBox1.Text += "Get_iMS_Link_Parameters Get_iMS_Link_Parameters Get_iMS_Link_Parameters\n";

            //程式所在位置
            string appPath = Application.ExecutablePath;
            //richTextBox1.Text += "本程式\n" + appPath + "\n";

            FileInfo finfo = new FileInfo(appPath);
            //richTextBox1.Text += finfo.Name + "\n";
            //richTextBox1.Text += finfo.Name + "\t" + finfo.FullName + "\t" + finfo.Length.ToString() + "\t" + finfo.CreationTime.ToShortDateString() + "\n";
            iMS_Link_exe_filename = finfo.Name;

            //若設定檔不存在 則需要先行建立一個
            if (File.Exists(iMS_Link_ini_filename) == false)   //確認檔案是否存在
            {
                richTextBox1.Text += "檔案 : " + iMS_Link_ini_filename + ", 不存在, 需要先建立一個\n";
                create_iMS_Link_ini_filename();
            }

            //先讀.ini的設定  若這部分可用 就不要再用系統參數了
            richTextBox1.Text += "Read ini data from " + iMS_Link_ini_filename + "\n";
            StringBuilder temp = new StringBuilder(1024);//定義一個最大長度為1024的可變字符串

            string section_name = "SetupWRITE_DATA";
            if (flag_automation_mode == MODE_WRITE_DATA)
            {
                //燒錄
                section_name = "SetupWRITE_DATA";
            }
            else
            {
                //色調
                section_name = "SetupAWB";
            }

            string parameter_name = "ComportName";
            GetPrivateProfileString(section_name, parameter_name, "", temp, 255, iMS_Link_ini_filename);
            if (temp.Length > 2)
                COM_Port_OK_Name = temp.ToString();
            //richTextBox1.Text += "取得資料 : " + temp + "\n";
            //richTextBox1.Text += "COM_Port_OK_Name : " + COM_Port_OK_Name + "\n";

            parameter_name = "Language";
            GetPrivateProfileString(section_name, parameter_name, "", temp, 255, iMS_Link_ini_filename);
            if (temp.Length > 0)
                SelectedLanguage = int.Parse(temp.ToString());
            //richTextBox1.Text += "取得資料 : " + temp + "\n";
            //richTextBox1.Text += "取得資料len : " + temp.Length.ToString() + "\n";
            //richTextBox1.Text += "SelectedLanguage : " + SelectedLanguage.ToString() + "\n";

            //CSV路徑
            parameter_name = "CSVPath";
            string data = GetIniFileValue(section_name, parameter_name, iMS_Link_ini_filename);
            //richTextBox1.Text += data + "\n";
            //richTextBox1.Text += "len = " + data.Length.ToString() + "\n";
            automation_save_data_path = data;

            //圖片路徑
            parameter_name = "PicturePath";
            data = GetIniFileValue(section_name, parameter_name, iMS_Link_ini_filename);
            //richTextBox1.Text += data + "\n";
            //richTextBox1.Text += "len = " + data.Length.ToString() + "\n";
            automation_save_picture_path = data;

            //相機路徑
            parameter_name = "CameraName";
            data = GetIniFileValue(section_name, parameter_name, iMS_Link_ini_filename);
            //richTextBox1.Text += data + "\n";
            //richTextBox1.Text += "len = " + data.Length.ToString() + "\n";
            insighteyes_name = data;

            richTextBox1.Text += "取得資料路徑 : " + automation_save_data_path + "\n";
            richTextBox1.Text += "取得圖片路徑 : " + automation_save_picture_path + "\n";
            richTextBox1.Text += "取得相機名稱 : " + insighteyes_name + "\n";


            /* TBD 待轉換成使用 讀 .ini檔

            int awb_brightness_upper_limit = Properties.Settings.Default.awb_brightness_upper_limit;
            int awb_brightness_lower_limit = Properties.Settings.Default.awb_brightness_lower_limit;
            richTextBox1.Text += "取得AWB亮度上限 : " + awb_brightness_upper_limit.ToString() + "\n";
            richTextBox1.Text += "取得AWB亮度下限 : " + awb_brightness_lower_limit.ToString() + "\n";

            */

            bool flag_need_restore_default = Properties.Settings.Default.restore_default;
            richTextBox1.Text += "是否強制恢復預設值 : " + flag_need_restore_default.ToString() + "\n";

            //取得檔案資訊
            string file_compile_time = "123456";
            if (File.Exists(iMS_Link_exe_filename) == false)   //確認檔案是否存在
            {
                richTextBox1.Text += "檔案 : " + iMS_Link_exe_filename + ", 不存在\n";
            }
            else
            {
                file_compile_time = File.GetLastWriteTime(iMS_Link_exe_filename).ToString("yyyy/MM/dd HH:mm:ss");
                richTextBox1.Text += "檔案時間 : " + file_compile_time + "\n";
            }

            /*
            //取得檔案資訊, same
            FileInfo fi = new FileInfo(iMS_Link_exe_filename);
            if (fi.Exists == true)      //確認檔案是否存在
            {
                richTextBox1.Text += "最近寫入時間 : " + fi.LastWriteTime.ToString() + Environment.NewLine;
            }
            else
                richTextBox1.Text += "檔案 : " + iMS_Link_exe_filename + ", 不存在\n";
            */

            if (flag_need_restore_default == true)
            {
                richTextBox1.Text += "依要求強制恢復預設值\n";
            }

            if (flag_need_restore_default == true)
            {
                int operation_mode = 0;	//0: 色彩調教, 1: 資料燒錄
                if (AUTOMATION_MODE == MODE_WRITE_DATA)
                {
                    operation_mode = 1;
                }
                else
                {
                    operation_mode = 0;
                }
                Properties.Settings.Default.operation_mode = operation_mode;

                bool automation_factory_mode = AUTOMATION_FACTORY_MODE;
                Properties.Settings.Default.factory_mode = automation_factory_mode;

                //是否使用真的PLC, true: 真上位PLC, false: 假上位, 偽裝PLC上位來下命令
                bool automation_use_plc = AUTOMATION_USE_PLC;
                Properties.Settings.Default.automation_use_plc = automation_use_plc;

                //是否使用真的 IMS 執行 燒錄 或 色調, true: 真下位, false: 假下位
                bool automation_use_ims = AUTOMATION_USE_IMS;
                Properties.Settings.Default.automation_use_ims = automation_use_ims;

                //內視鏡種類 0: 胃鏡, 1: 食道鏡
                int egd_type = AUTOMATION_EGD_TYPE;
                Properties.Settings.Default.egd_type = egd_type;

                Properties.Settings.Default.restore_default = false;
                Properties.Settings.Default.Save();
            }
            else
            {
                richTextBox1.Text += "無需恢復預設值\n";
            }

            flag_factory_mode = Properties.Settings.Default.factory_mode;
            if (flag_factory_mode == true)
            {
                richTextBox1.Text += "工廠模式\n";
                flag_use_specific_ims = false; //不用 指明對應主機
                flag_operation_mode = MODE_RELEASE_STAGE0;
                lb_automation_message2.Text = "工廠模式";
            }
            else
            {
                richTextBox1.Text += "一般模式\n";
                flag_use_specific_ims = true; //要 指明對應主機
                flag_operation_mode = MODE_RELEASE_STAGE2;
                lb_automation_message2.Text = "一般模式";
            }
        }

