            else if (((Button)sender).Name == "bt_debug23")
            {
                bt_debug23_Click(sender, e);
            }
            else if (((Button)sender).Name == "bt_debug24")
            {
                bt_debug24_Click(sender, e);
            }
            else if (((Button)sender).Name == "bt_debug25")
            {
                bt_debug25_Click(sender, e);
            }
            else if (((Button)sender).Name == "bt_debug26")
            {
                bt_debug26_Click(sender, e);
            }
            else
            {
                richTextBox1.Text += "XXXXXXXX 你按了按鈕 Name : " + ((Button)sender).Name + "\n";
            }
        }

