            groupBox5.Location = new Point(x_st, y_st);
            groupBox10.Location = new Point(x_st, y_st);
            groupBox14.Location = new Point(x_st, y_st);
            groupBox15.Location = new Point(x_st, y_st);
            groupBox16.Location = new Point(x_st, y_st);
            groupBox17.Location = new Point(x_st, y_st);
            groupBox18.Location = new Point(x_st, y_st);
            groupBox19.Location = new Point(x_st, y_st);

            gb_w = 850;
            gb_h = 200;
            x_st = 30;
            y_st = 30;

            groupBox11.Size = new Size(gb_w, gb_h);     //連線-相機狀態
            groupBox3.Size = new Size(gb_w, gb_h);      //連線-主機時間
            groupBox11.Location = new Point(x_st, y_st);

            y_st = 260;
            groupBox3.Location = new Point(x_st, y_st);

            panel1.Location = new Point(x_st + gb_w - 160, y_st + gb_h + 20);

            int margin = 50;

            pictureBox3.BackColor = Color.LightGray;
            pictureBox3.Visible = false;
            pictureBox3.Location = new Point(pictureBox3_position_x_old, pictureBox3_position_y_old);

