            // 實例化按鈕
            btn1.Width = 60;
            btn1.Height = 40;
            btn1.Text = "Play";
            btn1.Name = "bt_play";
            btn1.Location = new Point((256 * 2 + margin * 2) / 2 + 50, (256 * 2 + margin * 2) - btn1.Height - 5);
            // 加入按鈕事件
            //btn1.Click += new EventHandler(myClick1);   //same
            btn1.Click += myClick1;
