            hsbar.Width = 250;
            hsbar.Height = 30;
            hsbar.Maximum = 99;
            hsbar.Minimum = 1;
            hsbar.Value = 50;
            hsbar.LargeChange = 1;
            hsbar.SmallChange = 1;
            hsbar.Name = "hsbar1";

