        private void timer_clock_Tick(object sender, EventArgs e)
        {
            if (flag_use_metering_color == true)
            {
                measure_picture();
            }

            if (flag_use_measure_picture_brightness == true)
            {
                show_picture_brightness();
            }

            if (flag_show_cmx_lenc_result == true)
            {
                show_cmx_lenc_result();
            }

            if (flag_show_ov_test_result == true)
            {
                show_ov_test_result();
            }

            //toolStripStatusLabel1.Text = DateTime.Now.ToString("yyyy/MM/dd HH:mm:ss");

            //richTextBox1.Text += "flag_right_left = " + flag_right_left_cnt.ToString() + " flag_down_up_cnt = " + flag_down_up_cnt.ToString() + "\n";

            Application.DoEvents();

            string[] Day = new string[] { "Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat" };
            string weekday = Day[Convert.ToInt32(DateTime.Now.DayOfWeek.ToString("d"))].ToString();
            //richTextBox1.Text += weekday + "\n";
            lb_time1.Text = "PC時間 : " + DateTime.Now.ToString("yyyy" + '/' + "MM" + '/' + "dd ") + weekday + DateTime.Now.ToString(" HH" + ':' + "mm" + ':' + "ss");

            if (flag_network_disk_status == false)
            {
                if ((DateTime.Now.Second % 5) == 0)
                {
                    if (check_network_disk() == S_OK)
                    {
                        show_main_message1("已連上網路磁碟機", S_OK, 30);
                        show_main_message2("已連上網路磁碟機", S_OK, 30);
                        show_main_message3("已連上網路磁碟機", S_OK, 30);
                        tb_awb_mesg.BackColor = Color.White;
                        tb_awb_mesg.Text = "";
                    }
                }
            }

            //只有第0 1 2 3站才需要檢查ims相機
            if ((flag_operation_mode == MODE_RELEASE_STAGE0) || (flag_operation_mode == MODE_RELEASE_STAGE2)
    || (flag_operation_mode == MODE_RELEASE_STAGE1A) || (flag_operation_mode == MODE_RELEASE_STAGE1B) || (flag_operation_mode == MODE_RELEASE_STAGE3))
            {
                if (tabControl1.SelectedTab != tp_Serial_Auto)
                {
                    if (flag_ims_egd_exist == false)
                    {
                        /*
                        if ((DateTime.Now.Second % 5) == 0)
                        {
                            if (check_ims_camera() == S_OK)
                            {
                                flag_ims_egd_exist = true;
                                show_main_message1("有ims相機", S_OK, 30);
                                show_main_message2("有ims相機", S_OK, 30);
                                show_main_message3("有ims相機", S_OK, 30);
                                tb_awb_mesg.BackColor = Color.White;
                                tb_awb_mesg.Text = "";
                            }
                            else
                                flag_ims_egd_exist = false;
                        }
                        */
                    }
                }
            }

            if ((flag_operation_mode <= MODE_RELEASE_STAGE3) || (flag_operation_mode == MODE_RELEASE_STAGE1A) || (flag_operation_mode == MODE_RELEASE_STAGE1B) || (flag_operation_mode == MODE_RELEASE_STAGE1C))
            {
                if ((DateTime.Now.Second % 2) == 0)
                {
                    DateTime dt = DateTime.Now;
                    /*
                    //richTextBox1.Text += dt.Hour.ToString("00") + ":" + dt.Minute.ToString("00") + ":" + dt.Second.ToString("00") + "." + dt.Millisecond.ToString("000") + "\n";
                    //richTextBox1.Text += "frame_count = " + frame_count.ToString() + "\n";
                    //richTextBox1.Text += "frame diff = " + (frame_count - frame_count_old).ToString() + "\n";
                    //richTextBox1.Text += "time diff = " + (dt - dt_old).ToString() + "\n";
                    //richTextBox1.Text += "time diff in ms = " + ((TimeSpan)(dt - dt_old)).TotalMilliseconds.ToString() + "\n";
                    //richTextBox1.Text += "fps = " + (((frame_count - frame_count_old)*1000)/((TimeSpan)(dt - dt_old)).TotalMilliseconds).ToString() + "\n";
                    */
                    if (flag_use_metering == false)
                    {
                        double fps = (((frame_count - frame_count_old) * 1000) / ((TimeSpan)(dt - dt_old)).TotalMilliseconds);
                        lb_fps.Text = fps.ToString("F2") + " fps";

                        if (fps < 5)
                        {
                            pictureBox_fps.BackgroundImage = iMS_Link.Properties.Resources.face3;
                        }
                        else if (fps < 25)
                        {
                            pictureBox_fps.BackgroundImage = iMS_Link.Properties.Resources.face2;
                        }
                        else
                        {
                            pictureBox_fps.BackgroundImage = iMS_Link.Properties.Resources.face1;
                        }

                        if (flag_enaglb_automation == true)
                        {
                            if (fps < 1)
                            {
                                pbx_ims_connection4.BackgroundImage = Properties.Resources.ims_connection4_OFF;
                                lb_automation_message3.Text = "無影像";
                                lb_automation_message3.ForeColor = Color.Red;
                                lb_plc_awb_video_message.Text = "無影像";
                                lb_plc_awb_video_message.ForeColor = Color.Red;
                                flag_video_ok_for_awb = false;
                            }
                            else if (fps < 15)
                            {
                                pbx_ims_connection4.BackgroundImage = Properties.Resources.ims_connection4_OFF;
                                lb_automation_message3.Text = "低畫質";
                                lb_automation_message3.ForeColor = Color.Yellow;
                                lb_plc_awb_video_message.Text = "無影像";
                                lb_plc_awb_video_message.ForeColor = Color.Yellow;
                                flag_video_ok_for_awb = false;
                            }
                            else if (fps < 25)
                            {
                                pbx_ims_connection4.BackgroundImage = Properties.Resources.ims_connection4_OFF;
                                lb_automation_message3.Text = "中畫質";
                                lb_automation_message3.ForeColor = Color.Gold;
                                lb_plc_awb_video_message.Text = "中畫質";
                                lb_plc_awb_video_message.ForeColor = Color.Gold;
                                flag_video_ok_for_awb = false;
                            }
                            else
                            {
                                pbx_ims_connection4.BackgroundImage = Properties.Resources.ims_connection4_ON;
                                lb_automation_message3.Text = "正常影像";
                                lb_automation_message3.ForeColor = Color.Green;
                                lb_plc_awb_video_message.Text = "正常影像";
                                lb_plc_awb_video_message.ForeColor = Color.Green;
                                flag_video_ok_for_awb = true;
                            }
                        }
                    }
                    dt_old = dt;
                    frame_count_old = frame_count;
                }
            }
        }

        public double hex2dec(string hex_data)
        {
            byte value = 0;
            double dec_value = 0;
            //MessageBox.Show("data = " + hex_data);
            for (int i = 0; i < hex_data.Length; i++)
            {
                if ((hex_data[i] >= (Char)48 && hex_data[i] <= (Char)57))
                {
                    value = (byte)(hex_data[i] - 48);

                }
                else if ((hex_data[i] >= 'A') && (hex_data[i] <= 'F'))
                {
                    value = (byte)(hex_data[i] - 'A' + 10);
                }
                else if ((hex_data[i] >= 'a') && (hex_data[i] <= 'f'))
                {
                    value = (byte)(hex_data[i] - 'a' + 10);
                }
                dec_value = dec_value * 16 + value;
                //MessageBox.Show("data : " + hex_data[i] + " value : " + value);
            }
            return dec_value;
        }

