        public bool Send_IMS_Data2(int addr, byte dd)
        {
            if (get_comport_status() == false)
                return false;

            Send_IMS_Data_cnt++;
            //serialPort2.DiscardInBuffer();    //can not use this

            byte[] data = new byte[5];

            data[0] = 0xA0;
            data[1] = (byte)((addr >> 8) & 0xff);
            data[2] = (byte)(addr & 0xff);
            data[3] = dd;
            data[4] = CalcCheckSum(data, 4);

            /*
            if ((xx == 0x35) && (yy == 0x01))
            {
                richTextBox1.AppendText("xxxxxxxxxxx  [TX] : " + ((int)data[0]).ToString("X2") + " " + ((int)data[1]).ToString("X2") + " " + ((int)data[2]).ToString("X2") + " " + ((int)data[3]).ToString("X2") + " " + ((int)data[4]).ToString("X2") + "\n");
