        private void button8_Click(object sender, EventArgs e)
        {
            if (get_comport_status() == false)
                return;

            g_conn_status = get_camera_status();

            if (g_conn_status != CAMERA_OK)
                return;

            button8.BackColor = Color.Red;
            lb_write_camera_serial2.Text = "有連接器, 有相機";
            lb_write_camera_serial2.BackColor = Color.White;

            g2.Clear(BackColor);
            textBox7.Clear();
            textBox7.BackColor = Color.Gray;
            tb_sn1.Clear();
            tb_sn2.Clear();
            tb_sn1.BackColor = Color.Gray;
            tb_info_aa1.Clear();
            tb_info_aa2.Clear();
            lb_sn1.Text = "相機序號1 讀取中...";
            lb_sn2.Text = "相機序號2 讀取中...";
            lb_sn3.Text = "";
            lb_write_camera_serial2.Text = "";
            lb_a.Text = "";

            Get_IMS_Data(0, 0xAA, 0xAA);    //camera serial read

            int cnt = 0;
            while ((flag_wait_receive_data == 1) && (cnt++ < 20))
            {
                richTextBox1.Text += "+";
                delay(100);
            }
            flag_wait_receive_data = 0;

            byte page;
            page = DATE_PAGE0;  //serial date, product time
            Get_IMS_Data(1, page, 0xAA);    //read camera page 10 for product time
            cnt = 0;
            while ((flag_wait_receive_data == 1) && (cnt++ < 20))
            {
                richTextBox1.Text += "+";
                delay(100);
            }
            flag_wait_receive_data = 0;

            lb_write_camera_serial2.BackColor = Color.White;
            lb_write_camera_serial2.Text = "讀取序號資料完成";
            button8.BackColor = SystemColors.ControlLight;

            richTextBox1.Text += "讀取 軟體版本資訊\n";

            page = SW_VERSION_PAGE; //儲存軟體版本資訊
            Get_IMS_Data(1, page, 0xAA);    //read camera page 10 for product time
            cnt = 0;
            while ((flag_wait_receive_data == 1) && (cnt++ < 20))
            {
                richTextBox1.Text += "+";
                delay(100);
            }
            flag_wait_receive_data = 0;
        }

        private void button28_Click(object sender, EventArgs e)
        {
            if (get_comport_status() == false)
                return;
            flag_read_camera_raw_data = 1;
            textBox5.Clear();
            int page = Convert.ToInt32(textBox6.Text, 16);
            Send_IMS_Data(0xD1, (byte)page, 0, 0);
            return;
        }

