        //自定義函數, 捕獲每一幀圖像並顯示
        void Cam_NewFrame(object sender, NewFrameEventArgs eventArgs)
        {
            if (flag_get_camera_frame_for_saving == true)
            {
                bm_save = (Bitmap)eventArgs.Frame.Clone();
                flag_get_camera_frame_for_saving = false;
                return;
            }

            if (flag_ims_egd_exist == false)
            {
                try
                {
                    //pictureBox1.Image = (Bitmap)eventArgs.Frame.Clone();  //直接顯示圖片, 但是通常會先做些處理再顯示
                    bm = (Bitmap)eventArgs.Frame.Clone();
                    //bm.RotateFlip(RotateFlipType.RotateNoneFlipY);    //反轉
                    //pictureBox1.Image = bm;
                }
                catch (Exception ex)
                {
                    richTextBox1.Text += "xxx錯誤訊息e04 : " + ex.Message + "\n";
                }

                try
                {
                    pictureBox1.Image = bm;
                }
                catch (Exception ex)
                {
                    richTextBox1.Text += "xxx錯誤訊息e05 : " + ex.Message + "\n";
                }

                GC.Collect();       //回收資源
                return;
            }

            if (flag_do_find_awb_location == true)
                return;

            if (flag_capture_picture == true)
            {
                richTextBox1.Text += "xxx Cam_NewFrame! ";
                return;
            }

            flag_capture_picture = true;

            int x_st = 0;
            int y_st = 0;
            int dy = 40;
            int ww = awb_block;
            int hh = awb_block;

            if (g_conn_status != CAMERA_OK)
            {
                //richTextBox1.Text += "QQQ ";
            }

            frame_count++;
            if ((flag_enaglb_awb_function == true) || (flag_check_webcam_signal == true))
            {
                frame_cnt++;
                if ((frame_cnt % 5) == 0)
                {
                    //Bitmap bitmap1 = (Bitmap)pictureBox1.Image;
                    Bitmap bitmap1 = (Bitmap)eventArgs.Frame.Clone();
                    //bitmap1.RotateFlip(RotateFlipType.RotateNoneFlipX);

                    int WW = bitmap1.Width;
                    int HH = bitmap1.Height;
                    int i;
                    int j;
                    Color pt;
                    x_st = WW / 2 - ww / 2 + flag_right_left_cnt * awb_step + flag_right_left_point_cnt;
                    if (x_st < 0)
                        x_st = 0;
                    if ((x_st + ww) > WW)
                        x_st = WW - ww;

                    y_st = HH / 2 - hh / 2 + flag_down_up_cnt * awb_step + flag_down_up_point_cnt;
                    if (y_st < 0)
                        y_st = 0;
                    if ((y_st + hh) > HH)
                        y_st = HH - hh;

                    total_R = 0;
                    total_G = 0;
                    total_B = 0;

                    for (j = 0; j < hh; j++)
                    {
                        for (i = 0; i < ww; i++)
                        {
                            pt = bitmap1.GetPixel(x_st + i, y_st + j);
                            total_R += pt.R;
                            total_G += pt.G;
                            total_B += pt.B;
                        }
                    }
                    GC.Collect();       //回收資源

                    total_RGB_R = total_R;
                    total_RGB_G = total_G;
                    total_RGB_B = total_B;

                    if (cb_Contrast_Brightness_Gamma.Checked == true)
                    {
                        Color pt2;
                        for (i = 0; i < 8; i++)
                        {
                            x_st = i * 80 + 20;
                            y_st = 300;

                            pt2 = bitmap1.GetPixel(x_st, y_st);
                            y_data_r[i] = pt2.R;
                            y_data_g[i] = pt2.G;
                            y_data_b[i] = pt2.B;

                            RGB pp = new RGB(pt2.R, pt2.G, pt2.B);
                            YUV yyy = new YUV();
                            yyy = RGBToYUV(pp);

                            y_data_y[i] = (int)yyy.Y;
                        }
                    }

                }

                if (flag_show_brightness == true)
                {
                    if ((frame_cnt % 33) == 0)
                    {
                        show_picture_brightness_histogram();
                    }
                }
            }

            try
            {
                //pictureBox1.Image = (Bitmap)eventArgs.Frame.Clone();
                bm = (Bitmap)eventArgs.Frame.Clone();
                //bm.RotateFlip(RotateFlipType.RotateNoneFlipX);
                //pictureBox1.Image = bm;
            }
            catch (Exception ex)
            {
                richTextBox1.Text += "xxx錯誤訊息e06 : " + ex.Message + "\n";
                GC.Collect();       //回收資源
                flag_capture_picture = false;
                return;
            }

            try
            {
                gg = Graphics.FromImage(bm);
            }
            catch (Exception ex)
            {
                richTextBox1.Text += "xxx錯誤訊息e07 : " + ex.Message + "\n";
