            {
                w = bm.Width;
                h = bm.Height;
            }
            catch (Exception ex)
            {
                richTextBox1.Text += "xxx錯誤訊息e08a : " + ex.Message + "\n";
                GC.Collect();       //回收資源
                flag_capture_picture = false;
                return;
            }

            //設定要抓取的區域
            //RectangleF rect = new RectangleF(zoom_step * zoom_cnt / 2, zoom_step * zoom_cnt * 3 / 4 / 2, w - zoom_step * zoom_cnt, h - zoom_step * zoom_cnt * 3 / 4);
            //RectangleF rect = new RectangleF(zoom_step * zoom_cnt / 2 + zoom_step * (btn_right_cnt - btn_left_cnt) / 2, zoom_step * zoom_cnt * 3 / 4 / 2, w - zoom_step * zoom_cnt, h - zoom_step * zoom_cnt * 3 / 4);
            RectangleF rect = new RectangleF(zoom_step * zoom_cnt / 2 + zoom_step * btn_right_left_cnt / 2,
                                             (zoom_step * zoom_cnt / 2 + zoom_step * btn_down_up_cnt / 2) * 3 / 4,
                                             w - zoom_step * zoom_cnt, h - zoom_step * zoom_cnt * 3 / 4);

            if (flag_measure_brightness == true)
            {
                int WW = 640;
                int HH = 480;
                x_st = WW / 2 - ww / 2 + flag_right_left_cnt * awb_step + flag_right_left_point_cnt;
                if (x_st < 0)
                    x_st = 0;
                if ((x_st + ww) > WW)
                    x_st = WW - ww;

                y_st = HH / 2 - hh / 2 + flag_down_up_cnt * awb_step + flag_down_up_point_cnt;
                if (y_st < 0)
                    y_st = 0;
                if ((y_st + hh) > HH)
                    y_st = HH - hh;

                if ((frame_cnt_brightness % 30) == 0)
                {
                    measure_brightness_result = measure_brightness2(x_st, y_st, ww, hh);
                    //richTextBox1.Text += "x_st = " + x_st.ToString() + ", y_st = " + y_st.ToString() + "\t";
                    //richTextBox1.Text += "ww = " + ww.ToString() + ", hh = " + hh.ToString() + "\n";
                }
                show_brightness_data = ww.ToString() + " X " + hh.ToString() + "\n" + ((int)measure_brightness_result).ToString() + "." + (((int)(measure_brightness_result * 1000)) % 1000).ToString();
                drawBrush = new SolidBrush(Color.Gold);
                drawFont1 = new Font("Arial", 4, FontStyle.Bold, GraphicsUnit.Millimeter);
                gg.DrawString(show_brightness_data, drawFont1, drawBrush, x_st, y_st - 36);

                gg.DrawRectangle(new Pen(Color.Green, 1), x_st, y_st, ww, hh);

                frame_cnt_brightness++;
            }

            if (flag_show_cmx_brightness == true)
            {
                int cx = 640 / 2;
                int cy = 480 / 2;
                int www = 32;
                int hhh = 32;
                Font drawFont4 = new Font("Arial", 4, FontStyle.Bold, GraphicsUnit.Millimeter);

                drawBrush = new SolidBrush(Color.Gold);
                gg.DrawString(www.ToString() + "X" + hhh.ToString(), drawFont4, drawBrush, cx + www / 2 - 56, cy - hhh / 2 - 26);

                //gg.DrawRectangle(new Pen(Color.Green, 1), cx - www / 2, cy - hhh / 2, www, hhh);
                //把最亮的3成塗成紅色
                int i = 0;
                int j = 0;
                int ii = 0;
                //找出所有亮度值
                int[] R_data = new int[www * hhh];
                int[] G_data = new int[www * hhh];
                int[] B_data = new int[www * hhh];
                int[] Y_data = new int[www * hhh];
                for (j = cy - hhh / 2; j < cy + hhh / 2; j++)
                {
                    for (i = cx - www / 2; i < cx + www / 2; i++)
                    {
                        Color pt = bm.GetPixel(i, j);
                        R_data[ii] = (int)pt.R;
                        G_data[ii] = (int)pt.G;
                        B_data[ii] = (int)pt.B;

                        byte r = pt.R;
                        byte g = pt.G;
                        byte b = pt.B;
                        //byte gray = (byte)((r+g+b)/3);
                        //Color pt_new = Color.FromArgb(255, gray,gray,gray);
                        //bm.SetPixel(i, j, pt_new);

                        RGB pp = new RGB(pt.R, pt.G, pt.B);
                        YUV yyy = new YUV();
                        yyy = RGBToYUV(pp);
                        Y_data[ii] = (int)yyy.Y;
                        ii++;

                        if (yyy.Y > 200)
                        {
                            //bm.SetPixel(i, j, Color.Red);
                        }
                    }
                }

                R_data_average[data_average_index] = R_data.Sum();
                G_data_average[data_average_index] = G_data.Sum();
                B_data_average[data_average_index] = B_data.Sum();
                Y_data_average[data_average_index] = Y_data.Sum();
                data_average_index++;
                if (data_average_index >= AVERAGE_FRAME)
                    data_average_index = 0;

                //畫出邊界與寫上平均值
                gg.DrawRectangle(new Pen(Color.Gold, 5), cx - www / 2 - 5, cy - hhh / 2 - 5, www + 10, hhh + 10);

                drawFont4 = new Font("Arial", 6, FontStyle.Bold, GraphicsUnit.Millimeter);

                x_st = cx + www / 2 + 35;
                y_st = cy - hhh / 2 - 20;
                string average = ((float)R_data.Sum() / R_data.Length).ToString("F1");
                drawBrush = new SolidBrush(Color.Red);
                gg.DrawString(average, drawFont4, drawBrush, x_st, y_st);

                average = ((float)G_data.Sum() / G_data.Length).ToString("F1");
                drawBrush = new SolidBrush(Color.Green);
                gg.DrawString(average, drawFont4, drawBrush, x_st, y_st + 30);

                average = ((float)B_data.Sum() / B_data.Length).ToString("F1");
                drawBrush = new SolidBrush(Color.Blue);
                gg.DrawString(average, drawFont4, drawBrush, x_st, y_st + 60);

                average = ((float)Y_data.Sum() / Y_data.Length).ToString("F1");
                drawBrush = new SolidBrush(Color.Gold);
                gg.DrawString(average, drawFont4, drawBrush, x_st, y_st + 90);

                average = ((float)R_data_average.Sum() / (www * hhh * R_data_average.Length)).ToString("F1");
                drawBrush = new SolidBrush(Color.Red);
                gg.DrawString(average, drawFont4, drawBrush, x_st + 80, y_st);

                average = ((float)G_data_average.Sum() / (www * hhh * G_data_average.Length)).ToString("F1");
                drawBrush = new SolidBrush(Color.Green);
                gg.DrawString(average, drawFont4, drawBrush, x_st + 80, y_st + 30);

                average = ((float)B_data_average.Sum() / (www * hhh * B_data_average.Length)).ToString("F1");
                drawBrush = new SolidBrush(Color.Blue);
                gg.DrawString(average, drawFont4, drawBrush, x_st + 80, y_st + 60);

                average = ((float)Y_data_average.Sum() / (www * hhh * Y_data_average.Length)).ToString("F1");
                drawBrush = new SolidBrush(Color.Gold);
                gg.DrawString(average, drawFont4, drawBrush, x_st + 80, y_st + 90);

                if (flag_show_cmx_brightness_center == true)
                {
                    //找出邊界
                    int length = Y_data.Length;
                    Array.Sort(Y_data);

                    int get = Y_data[www * hhh * (100 - flag_show_cmx_brightness_level) / 100];//最亮的10%
                    //show_main_message1(get.ToString(), S_OK, 30);

                    List<int[]> brightness_center = new List<int[]>();

                    for (j = cy - hhh / 2; j < cy + hhh / 2; j++)
                    {
                        for (i = cx - www / 2; i < cx + www / 2; i++)
                        {
                            Color pt = bm.GetPixel(i, j);
                            byte r = pt.R;
                            byte g = pt.G;
                            byte b = pt.B;
                            RGB pp = new RGB(pt.R, pt.G, pt.B);
                            YUV yyy = new YUV();
                            yyy = RGBToYUV(pp);
                            if (yyy.Y >= get)
                            {
                                //亮的塗上紅色
                                bm.SetPixel(i, j, Color.Red);
                                brightness_center.Add(new int[] { i, j });
                            }
                        }
                    }
                    if (brightness_center.Count > 0)
                    {
                        //richTextBox1.Text += "-" + brightness_center.Count.ToString() + "- ";

                        double xx = 0;
                        double yy = 0;
                        for (i = 0; i < brightness_center.Count; i++)
                        {
                            xx += brightness_center[i][0];
                            yy += brightness_center[i][1];
                            //richTextBox1.Text += "[" + xx.ToString() + "," + yy.ToString() + "] ";
                        }
                        //int brightness_center_x = (int)brightness_center[0].Average();
                        //int brightness_center_y = (int)brightness_center[1].Average();
                        int brightness_center_x = (int)(xx / brightness_center.Count);
                        int brightness_center_y = (int)(yy / brightness_center.Count);
                        //gg.FillEllipse(new SolidBrush(Color.Green), brightness_center_x-5, brightness_center_y-5, 10, 10);
                        int dd = 15;
                        x_st = brightness_center_x - dd;
                        y_st = brightness_center_y;
                        x_sp = brightness_center_x + dd;
                        y_sp = brightness_center_y;
                        gg.DrawLine(new Pen(Color.Gold, 3), x_st, y_st, x_sp, y_sp);
                        x_st = brightness_center_x;
                        y_st = brightness_center_y - dd;
                        x_sp = brightness_center_x;
                        y_sp = brightness_center_y + dd;
                        gg.DrawLine(new Pen(Color.Gold, 3), x_st, y_st, x_sp, y_sp);

                    }

                    //畫上標記
                    int total = hhh;
                    x_st = cx + www / 2 + 20;
                    y_st = cy - hhh / 2;
                    x_sp = x_st + 00;
                    y_sp = y_st + total;
                    gg.DrawLine(new Pen(Color.Silver, 7), x_st, y_st, x_sp, y_sp);

                    //int get = Y_data[www * hhh * (100 - flag_show_cmx_brightness_level) / 100];//最亮的10%
                    int red = (int)(hhh * flag_show_cmx_brightness_level / 100);
                    x_sp = x_st + 00;
                    y_sp = y_st + red;
                    gg.DrawLine(new Pen(Color.Red, 5), x_st, y_st, x_sp, y_sp);

                    drawFont4 = new Font("Arial", 4, FontStyle.Bold, GraphicsUnit.Millimeter);
                    drawBrush = new SolidBrush(Color.Gold);
                    x_st = cx + www / 2 + 10;
                    y_st = cy + hhh / 2 + 5;
                    gg.DrawString(flag_show_cmx_brightness_level.ToString() + " %", drawFont4, drawBrush, x_st, y_st);
                }
                if (flag_save_image_to_drive_with_brightness_info == true)
                {
                    flag_save_image_to_drive_with_brightness_info = false;

                    //顯示時間
                    drawDate = DateTime.Now.ToString("yyyy/MM/dd HH:mm:ss");
                    drawBrush = new SolidBrush(Color.Yellow);
                    drawFont1 = new Font("Arial", 6, FontStyle.Bold, GraphicsUnit.Millimeter);
                    x_st = 10;
                    y_st = 10;
                    //在畫面的上方顯示時間
                    gg.DrawString(drawDate, drawFont1, drawBrush, x_st, y_st);

