                    try
                    {
                        //bm.Save(@file1, ImageFormat.Jpeg);
                        bm.Save(filename, ImageFormat.Bmp);
                        //bm.Save(@file3, ImageFormat.Png);

                        richTextBox1.Text += "存檔成功2\n";
                        //richTextBox1.Text += "已存檔 : " + file1 + "\n";
                        richTextBox1.Text += "已存檔 : " + filename + "\n";
                        //richTextBox1.Text += "已存檔 : " + file3 + "\n";
                        show_main_message1("已存檔BMP", S_OK, 30);
                        show_main_message2("已存檔 : " + filename, S_OK, 30);
                    }
                    catch (Exception ex)
                    {
                        richTextBox1.Text += "xxx錯誤訊息e38a : " + ex.Message + "\n";
                        show_main_message1("存檔失敗", S_OK, 30);
                        show_main_message2("存檔失敗 : " + ex.Message, S_OK, 30);
                    }
                }
            }

            if ((cb_show_grid.Checked == true) && (flag_enaglb_awb_function == false))
            {   //顯示格線
                int i;
                int j;

                j = 0;
                if (rb_3X3.Checked == true)
                {
                    j = 3;
                }
                else if (rb_4X4.Checked == true)
                {
                    j = 4;
                }
                else if (rb_5X5.Checked == true)
                {
                    j = 80;
                }
                else if (rb_NXN.Checked == true)
                {
                    j = 160;
                }
                else
                {
                    j = 4;
                }

                if (flag_use_metering == false)
                {
                    if (j >= 2)
                    {
                        for (i = 1; i <= (j - 1); i++)
                        {
                            if (rb_gridlinecolor_white.Checked == true)
                            {
                                gg.DrawLine(new Pen(Color.Silver, 1), w * i / j, 0, w * i / j, h);
                                gg.DrawLine(new Pen(Color.Silver, 1), 0, h * i / j, w, h * i / j);
                            }
                            else
                            {
                                gg.DrawLine(new Pen(Color.Black, 1), w * i / j, 0, w * i / j, h);
                                gg.DrawLine(new Pen(Color.Black, 1), 0, h * i / j, w, h * i / j);
                            }
                        }
                    }
                }
                else
                {
                    int xx_st = 0;
                    int yy_st = 0;
                    int draw_x_st = 0;
                    int draw_y_st = 0;
                    double result = -1;
                    int www = 0;
                    int hhh = 0;

                    drawBrush = new SolidBrush(Color.Black);
                    drawFont1 = new Font("Arial", 4, FontStyle.Bold, GraphicsUnit.Millimeter);

                    if (rb_metering_1.Checked == true)
                    {
                        /*  部分圖
                        j = 5;
                        www = 16;
                        hhh = 12;

                        for (i = 1; i <= (j - 1); i++)
                        {
                            gg.DrawLine(new Pen(Color.Red, 1), w * i / j, 0, w * i / j, h);
                            gg.DrawLine(new Pen(Color.Red, 1), 0, h * i / j, w, h * i / j);
                        }


                        for (yy_st = h / (j * 2) - hhh / 2; yy_st < h; yy_st += h / j)
                        {
                            if (yy_st == (h / (j * 2) - hhh / 2 + (h / j) * 3))
                            {
                                for (xx_st = w / (j * 2) - www / 2; xx_st < w; xx_st += w / j)
                                {
                                    result = -1;
                                    result = measure_brightness2(xx_st, yy_st, www, hhh);

                                    gg.DrawRectangle(new Pen(Color.Red, 1), xx_st, yy_st, www, hhh);
                                    //richTextBox1.Text += "x_st = " + xx_st.ToString() + ", y_st = " + yy_st.ToString() + ", w = " + www.ToString() + ", h = " + hhh.ToString() + "\n";


                                    draw_x_st = xx_st - www / 2;
                                    draw_y_st = yy_st + hhh;

                                    string brightness = ((int)result).ToString() + "." + (((int)(result * 1000)) % 1000).ToString();

                                    drawBrush = new SolidBrush(Color.White);
                                    drawFont1 = new Font("Arial", 4, FontStyle.Bold, GraphicsUnit.Millimeter);
