        private void timer_display_Tick(object sender, EventArgs e)
        {
            if (timer_display_r_count < 10)
            {
                timer_display_r_count++;
                flag_display_r_do_awb = true;
            }
            else
                flag_display_r_do_awb = false;

            if (timer_display_g_count < 10)
            {
                timer_display_g_count++;
                flag_display_g_do_awb = true;
            }
            else
                flag_display_g_do_awb = false;

            if (timer_display_b_count < 10)
            {
                timer_display_b_count++;
                flag_display_b_do_awb = true;
            }
            else
                flag_display_b_do_awb = false;

            if (timer_display_show_main_mesg0_count < timer_display_show_main_mesg0_count_target)      //display main message timeout
            {
                timer_display_show_main_mesg0_count++;
                if (timer_display_show_main_mesg0_count >= timer_display_show_main_mesg0_count_target)
                {
                    lb_main_mesg0.Text = "";
                }
            }

            if (timer_display_show_main_mesg_cmx_lenc_count < timer_display_show_main_mesg_cmx_lenc_count_target)      //display main message timeout for cmx and lenc
            {
                timer_display_show_main_mesg_cmx_lenc_count++;
                if (timer_display_show_main_mesg_cmx_lenc_count >= timer_display_show_main_mesg_cmx_lenc_count_target)
                {
                    lb_main_mesg_cmx_lenc.Text = "";
                }
            }

            if (timer_display_show_main_mesg_count < timer_display_show_main_mesg_count_target)      //display main message timeout
            {
                timer_display_show_main_mesg_count++;
                if (timer_display_show_main_mesg_count >= timer_display_show_main_mesg_count_target)
                {
                    lb_main_mesg1.Text = "";
                    //lb_main_mesg2.Text = "";
                    lb_main_mesg3.Text = "";
                    lb_main_mesg11.Text = "";
                    lb_main_mesg12a.Text = "";
                }
                /*
                if (timer_display_show_main_mesg_count >= (timer_display_show_main_mesg_count_target * 2))
                {
                    //lb_main_mesg.Text = "";
                    lb_main_mesg2.Text = "";
                }
                */
            }
        }

        int try_connect_comport()
        {
            int ret = S_FALSE;
            //if (flag_comport_ok == true)  always close any comport
            {
                serialPort2.Close();
                this.BackColor = Color.Yellow;
                bt_comport_connect1b.Enabled = true;
                button89.Enabled = true;
                bt_comport_disconnect1b.Enabled = false;
                button90.Enabled = false;
                flag_comport_ok = false;
            }

            comboBox_comport1b.Items.Clear();    //Clear All items in Combobox
            comboBox_comport3.Items.Clear();    //Clear All items in Combobox
            richTextBox1.Text += "try_connect_comport ST\n";

            string[] tempString = SerialPort.GetPortNames();
            Array.Sort(tempString);
            Array.Resize(ref COM_Ports_NameArr, tempString.Length);
            tempString.CopyTo(COM_Ports_NameArr, 0);

            richTextBox1.Text += "c共抓到 " + tempString.Length.ToString() + " 個 comport :\t";
            foreach (string port in COM_Ports_NameArr)
            {
                richTextBox1.Text += port + "\t";
                comboBox_comport1b.Items.Add(port);
                comboBox_comport3.Items.Add(port);
            }
            richTextBox1.Text += "\n";

            if (COM_Ports_NameArr.Length == 0)
            {
                richTextBox1.Text += "沒有comport\n";
                flag_comport_ok = false;
                return S_FALSE;
            }
            else if (COM_Ports_NameArr.Length == 1)
            {
                comboBox_comport1b.Text = COM_Ports_NameArr[0];
                comboBox_comport3.Text = COM_Ports_NameArr[0];
            }
            else
            {
                comboBox_comport1b.Text = COM_Ports_NameArr[COM_Ports_NameArr.Length - 2];   //倒數第2個
                comboBox_comport3.Text = COM_Ports_NameArr[COM_Ports_NameArr.Length - 2];   //倒數第2個
            }

            if (COM_Ports_NameArr.Length == 1)
            {
                richTextBox1.Text += "只有一個comport, try 一次\n";
                ret = connect_comport(comboBox_comport1b.Text);
                if (ret == S_OK)
                    this.Text = "iMS_Link " + software_version + " " + comboBox_comport1b.Text;
                else
                    this.Text = "iMS_Link " + software_version;
            }
            else
            {
                richTextBox1.Text += "多個comport\n";

                int flag_comport_connected_ok = S_FALSE;

                if (flag_do_cmx_test == true)
                {
                    richTextBox1.Text += "測試cmx模式 : " + COM_Port_OK_Name + "\n";

                    COM_Port_OK_Name = "COM4";
                    comboBox_comport1b.Text = COM_Port_OK_Name;
                    comboBox_comport3.Text = COM_Port_OK_Name;

                    serialPort2.Close();
                    this.BackColor = Color.Yellow;
                    bt_comport_connect1b.Enabled = true;
                    button89.Enabled = true;
                    bt_comport_disconnect1b.Enabled = false;
                    button90.Enabled = false;
                    flag_comport_ok = false;

                    ret = connect_comport(COM_Port_OK_Name);
                    if (ret == S_OK)
                    {
                        richTextBox1.Text += "固定找到comport, 在 " + COM_Port_OK_Name + " a\n";
                        flag_comport_connected_ok = S_OK;
                        flag_comport_connected_name = COM_Port_OK_Name;
                        this.Text = "iMS_Link " + software_version + " " + flag_comport_connected_name;
                    }
                    else
                    {
                        richTextBox1.Text += "找優先連線 " + COM_Port_OK_Name + ", 但是連不上\n";
                    }
                }
                else if ((COM_Port_OK_Name.Length == 3) || (COM_Port_OK_Name.Length == 4) || (COM_Port_OK_Name.Length == 5))
                {
                    richTextBox1.Text += "優先尋找上次連線OK的comport : " + COM_Port_OK_Name + "\n";

                    comboBox_comport1b.Text = COM_Port_OK_Name;
                    comboBox_comport3.Text = COM_Port_OK_Name;

                    serialPort2.Close();
                    this.BackColor = Color.Yellow;
                    bt_comport_connect1b.Enabled = true;
                    button89.Enabled = true;
                    bt_comport_disconnect1b.Enabled = false;
                    button90.Enabled = false;
                    flag_comport_ok = false;

                    ret = connect_comport(COM_Port_OK_Name);
                    richTextBox1.Text += "\n";
                    if (ret == S_OK)
                    {
                        richTextBox1.Text += "優先找到可以連線到IMS EGD System的comport, 在 " + COM_Port_OK_Name + " a\n";
                        flag_comport_connected_ok = S_OK;
                        flag_comport_connected_name = COM_Port_OK_Name;
                        this.Text = "iMS_Link " + software_version + " " + flag_comport_connected_name;
                    }
                    else
                    {
                        richTextBox1.Text += "找優先連線 " + COM_Port_OK_Name + ", 但是連不上\n";
                    }
                }
                else
                {
                    richTextBox1.Text += "沒有上次連線OK的comport\n";
                }

                if (flag_comport_connected_ok == S_FALSE)
                {
                    int try_index;
                    for (int i = 0; i < COM_Ports_NameArr.Length; i++)
                    {
                        try_index = (i + COM_Ports_NameArr.Length - 2) % COM_Ports_NameArr.Length;  //從倒數第二個找起
                        //try_index = (i + COM_Ports_NameArr.Length - 1) % COM_Ports_NameArr.Length;  //從最後一個找起
                        //try_index = (0 + COM_Ports_NameArr.Length - 1) % COM_Ports_NameArr.Length;  //只找最後一個

                        //richTextBox1.Text += "try_index = " + try_index.ToString() + "\n";

                        comboBox_comport1b.Text = COM_Ports_NameArr[try_index];
                        comboBox_comport3.Text = COM_Ports_NameArr[try_index];

                        serialPort2.Close();
                        this.BackColor = Color.Yellow;
                        bt_comport_connect1b.Enabled = true;
                        button89.Enabled = true;
                        bt_comport_disconnect1b.Enabled = false;
                        button90.Enabled = false;
                        flag_comport_ok = false;

                        ret = connect_comport(COM_Ports_NameArr[try_index]);
                        richTextBox1.Text += "\n";
                        if (ret == S_OK)
                        {
                            richTextBox1.Text += "找到可以連線到IMS EGD System的comport, 在 " + COM_Ports_NameArr[try_index] + " b\n";
                            COM_Port_OK_Name = COM_Ports_NameArr[try_index];
                            flag_comport_connected_ok = S_OK;
                            flag_comport_connected_name = COM_Port_OK_Name;
                            this.Text = "iMS_Link " + software_version + " " + COM_Port_OK_Name;

                            if (flag_operation_mode == MODE_RELEASE_STAGE20)
                            {
                                this.tabControl1.SelectedTab.BackColor = Color.Transparent;
                                button91.Enabled = true;
                                button92.Enabled = true;
                                button93.Enabled = true;
                                bt_led_on.Enabled = true;
                                bt_led_off.Enabled = true;
                                bt_led_white.Enabled = true;
                                bt_led_nbi.Enabled = true;
                                button92.Visible = false;
                                button93.Visible = false;
                                this.tabControl1.Size = new Size(600, 600);
                                this.Size = new Size(640, 730);
                                this.tabControl1.Size = new Size(600 + 200 + 30, 600 + 100);
                                this.Size = new Size(640 + 200 + 30, 730 + 100);

                            }
                            break;
                        }
                    }
                }
            }

            if (ret == S_OK)
            {
                this.Text = "iMS_Link " + software_version + " " + flag_comport_connected_name;
                //計算serialPort2中有多少位元組 
                BytesToRead = serialPort2.BytesToRead;

                if (BytesToRead > 0)
                {
                    //開啟程式時, 把所有serialPort的資料讀出來, 並丟棄之
                    serialPort2.DiscardInBuffer();  //丟棄UART buffer內的資料
                }
                return S_OK;
            }
            else
                return S_FALSE;
        }

        int connect_comport(string comport)
        {
            if (flag_david_test3 == true)
            {
                this.Cursor = Cursors.Default;
                flag_comport_ok = true;
                return S_OK;
            }

            flag_comport_ok = false;
            serialPort2.PortName = comport;

            try
            {
                serialPort2.BaudRate = 115200;
            }
            catch (Exception ex)
            {
                richTextBox1.Text += "xxx錯誤訊息e16 : " + ex.Message + "\n";
                //MessageBox.Show("無法連上Comport, 請重新連線");
                richTextBox1.Text += "無法連上 " + comport + ", 請重新連線";
                bt_comport_connect1b.Enabled = true;
                button89.Enabled = true;
                bt_comport_disconnect1b.Enabled = false;
                button90.Enabled = false;
                this.BackColor = Color.Pink;
                flag_comport_ok = false;
            }

            //serialPort2.Open(); //原本是這一行，改寫成以下。
            try
            {   //可能會產生錯誤的程式區段
                richTextBox1.Text += "try to open " + comport + "\n";

                if (flag_enaglb_automation == true)
                {
                    lb_automation_message1.Text = "自動化作業啟動中";
                    if (flag_automation_mode == MODE_WRITE_DATA)
                    {
                        lb_automation_message1.Text += "(燒錄)";
                    }
                    else if (flag_automation_mode == MODE_AWB)
                    {
                        lb_automation_message1.Text += "(色調)";
                    }
                    else
                    {
                        lb_automation_message1.Text += "(其他)";
                    }
                    lb_automation_message1.Text += "...\n\n連線Comport : " + comport + " / " + flag_auto_connect_comport_round.ToString();
                    string message = "自動化作業啟動中";
                    send_message_to_iMS_LinkStarter(flag_automation_mode, 0, AUTOMATION_LEVEL2_BUSY, message);
                    flag_automation_status = S_OK;
                }
                serialPort2.Open();
            }
            catch (Exception ex)
            {   //定義產生錯誤時的例外處理程式碼
                richTextBox1.Text += "fail to open " + comport + ", reason : " + ex.Message + "\n";
                //MessageBox.Show(ex.Message);
            }
            finally
            {
                //一定會被執行的程式區段
                if (serialPort2.IsOpen)
                {
                    serialPort2.DtrEnable = true;   //白話地說就是通知儀器說我(電腦)這邊已經準備好了
                    //MessageBox.Show("已經連上" + serialPort2.PortName);

                    flag_comport_ok = true;
                    flag_comport_connection_ok = false;

                    //Application.DoEvents();

                    /*
                    //計算serialPort2中有多少位元組 
                    BytesToRead = serialPort2.BytesToRead;

                    if (BytesToRead > 0)
                    {
                        //開啟程式時, 把所有serialPort的資料讀出來, 並丟棄之
                        serialPort2.DiscardInBuffer();  //丟棄UART buffer內的資料
                    }
                    */
                    //delay(5);
                    serialPort2.DiscardInBuffer();  //丟棄UART buffer內的資料
                    SerialPortTimer100ms2.Stop();
                    SerialPortTimer100ms2.Start();
                    //Application.DoEvents();
                    //delay(5);

                    //計算serialPort2中有多少位元組 
                    BytesToRead = serialPort2.BytesToRead;

                    if (BytesToRead > 0)
                    {
                        richTextBox1.Text += "XXXXXX BytesToRead = " + BytesToRead.ToString() + "\n";
                    }

                    if (flag_enaglb_automation == false)
                    {
                        //一般使用
                        Send_IMS_Data0(0xFF, 0x11, 0x52, 0x00); //directly send uart command
                    }
                    else
                    {
                        if (flag_use_specific_ims == true)
                        {
                            //多台IMS主機連上同一台電腦 電腦要能區分不同主機

                            //發命令讀取主機板資訊
                            Send_IMS_Data(0xF1, 0xAB, 0xCD, 0xEF);  //main board model read
                        }
                        else
                        {
                            //自動化製程使用
                            if (flag_automation_mode == MODE_AWB)   //自動化製程 + 色調
                                Send_IMS_Data0(0xFF, 0x11, 0x52, 0xAB); //directly send uart command
                            else if (flag_automation_mode == MODE_WRITE_DATA)   //自動化製程 + 燒錄
                                Send_IMS_Data0(0xFF, 0x11, 0x52, 0xCD); //directly send uart command
                            else
                                Send_IMS_Data0(0xFF, 0x11, 0x52, 0x00); //directly send uart command
                        }
                    }

                    DateTime start_time = DateTime.Now;
                    //richTextBox1.Text += "時間1 : " + DateTime.Now.ToString() + "\n";
                    int cnt = 0;
                    while ((flag_comport_connection_ok == false) && (cnt++ < 60))
                    {
                        //richTextBox1.Text += "x";
                        delay(10);

                        //再發一次命令  TBD
                        /* TBD
                        if ((cnt % 15) == 14)
                        {
                            richTextBox1.Text += "無回應, 再發一次命令1\n";
                            Send_IMS_Data0(0xFF, 0x11, 0x52, 0x00); //directly send uart command
                            serialPort2.DiscardInBuffer();  //丟棄UART buffer內的資料
                            cnt = 0;
                        }
                        */
                    }

                    richTextBox1.Text += "\ncnt = " + cnt.ToString() + "\n";    //usually cnt = 4
                    if (cnt > 50)
                        richTextBox1.Text += "XXXXXXXXXXXXX warning\n";

                    if ((cnt > connect_comport_cnt_max) && (cnt < 41))
                    {
                        connect_comport_cnt_max = cnt;
                        richTextBox1.Text += "let cnt = " + cnt.ToString() + "\n";
                        //tb_awb_mesg.Text = connect_comport_cnt_max.ToString();
                        //Application.DoEvents();
                    }

                    //tb_awb_mesg.Text = connect_comport_cnt_max.ToString();
                    Application.DoEvents();

                    double diff_time = (DateTime.Now - start_time).TotalSeconds;
                    richTextBox1.Text += "時間 : " + diff_time.ToString() + "\n";
                    flag_comport_ok = false;

                    if (flag_comport_connection_ok == true)
                    {
                        if (serialPort2.IsOpen)
                        {
                            bt_comport_connect1b.Enabled = false;
                            button89.Enabled = false;
                            bt_comport_disconnect1b.Enabled = true;
                            button90.Enabled = true;
                            this.BackColor = SystemColors.ControlLight;
                            flag_comport_ok = true;
                        }
                        else
                        {
                            bt_comport_connect1b.Enabled = true;
                            button89.Enabled = true;
                            bt_comport_disconnect1b.Enabled = false;
                            button90.Enabled = false;
                            this.BackColor = Color.Pink;
                            flag_comport_ok = false;
                        }
                    }
                    else
                        flag_comport_ok = false;
                }
                else
                {
                    //MessageBox.Show("無法連上Comport, 請重新連線");
                    richTextBox1.Text += "無法連上 " + comport + ", 請重新連線";
                }
            }

            if (flag_comport_ok == true)
                return S_OK;
            else
                return S_FALSE;
        }

