            }

            page = Convert.ToInt32(textBox1.Text, 16);
            if ((page < USER_PAGE1) || (page > (USER_PAGE1 + 10)))
            {
                richTextBox1.Text += "不支援的flash位址 0x%" + page.ToString("X2") + "=" + page.ToString() + ", abort\n";
                return;
            }
            richTextBox1.Text += "寫入頁位置 = " + page.ToString() + "\n";

