        void exportCSV_AWB(string sn_opal, string awb_result, string awb_date)
        {
            richTextBox1.Text += "本地儲存AWB資料\n";
            String filename2 = Application.StartupPath + "\\csv\\ims_" + DateTime.Now.ToString("yyyyMMdd") + "_02_AWB.csv";

            string content = "";
            StreamWriter sw;
            int i;

            if (File.Exists(filename2) == false)   //確認檔案是否存在
            {
                richTextBox1.Text += "檔案: " + filename2 + " 不存在\n";

                if (flag_enaglb_automation == false)
                {
                    sw = new StreamWriter(File.Open(filename2, FileMode.Create), Encoding.Default);    //指名編碼格式
                }
                else
                {
                    sw = new StreamWriter(File.Open(filename2, FileMode.Create), Encoding.UTF8);    //指名編碼格式
                }
                content += "編號" + "," + "Opal序號" + "," + "色彩校正結果" + "," + "時間" + "," + "R" + "," + "B" + "," + "時間" + ",Y1,Y2,Y3,Y4,Y5,Y6,Y7,Y8,Y9,Y10,Y11,AWB R,AWB B,時間,左右,上下,大小,命令,R全,R,G全,G,B全,B\n";
            }
            else
            {
                richTextBox1.Text += "檔案: " + filename2 + " 已存在\n";
                try
                {
                    if (flag_enaglb_automation == false)
                    {
                        sw = new StreamWriter(File.Open(filename2, FileMode.Append), Encoding.Default);    //指名編碼格式
                    }
                    else
                    {
