        void reset_IMS_AWB()
        {
            richTextBox_plc.Text += "斷電重開 AWB\n";
            Application.DoEvents();
            string url = @"http://192.168.2.123/set.cmd?user=admin+pass=12345678+cmd=setpowercycle&p62=1";
            richTextBox_plc.Text += "reset\n";
            //WebClient wc = new WebClient();
            MyWebClient wc = new MyWebClient();
            wc.Encoding = Encoding.UTF8;
            try
            {
                string html = wc.DownloadString(url);
                richTextBox_plc.Text += html + "\n";
            }
            catch (WebException ex)
            {
                richTextBox_plc.Text += "WebException\t" + ex.Message + "\n";
            }
            catch (Exception ex)
            {
                richTextBox_plc.Text += "Error\t" + ex.Message + "\n";
            }
        }

