            openFileDialog1.FilterIndex = 1;
            openFileDialog1.RestoreDirectory = true;
            openFileDialog1.InitialDirectory = Application.StartupPath + "\\script\\";         //從目前目錄開始尋找檔案
            if (openFileDialog1.ShowDialog() == DialogResult.OK)
            {
                richTextBox1.Text += "1 get filename : " + openFileDialog1.FileName + "\n";
                //richTextBox1.Text += "length : " + openFileDialog1.FileName.Length.ToString() + "\n";

                flag_script_data_on = true;
                richTextBox2.Visible = true;
                bt_script_apply.Visible = true;
                bt_script_save.Visible = true;
                bt_script_cancel.Visible = true;
                bt_cancel.Visible = true;
                bt_script.Text = "Apply";

                if (flag_display_mode == DISPLAY_SD)
                {
                    show_main_message1("Mode0不支援SD螢幕", S_FALSE, 30);
                    show_main_message2("Mode0不支援SD螢幕", S_FALSE, 30);
                    show_main_message3("Mode0不支援SD螢幕", S_FALSE, 30);
                }
                else
                {
                    int x_st;
                    int y_st;
                    x_st = 605;
                    y_st = 500;
                    richTextBox2.Location = new Point(x_st, y_st);
                    richTextBox2.Size = new Size(300, 450);
                    bt_script_apply.Location = new Point(x_st + 300 - bt_script_save.Width - 10, y_st + 10);
                    bt_script_save.Location = new Point(x_st + 300 - bt_script_save.Width - 10, y_st + 10 + 35);
                    bt_script_cancel.Location = new Point(x_st + 300 - bt_script_save.Width - 10, y_st + bt_script_save.Height + 10 + 70);
                }
                richTextBox2.Clear();

                //StreamReader sr = new StreamReader(openFileDialog1.FileName);
                //StreamReader sr = new StreamReader(fileName, Encoding.Default);
                StreamReader sr = new StreamReader(openFileDialog1.FileName, Encoding.Default);	//Encoding.Default解決讀取一般編碼檔案中文字錯亂的問題
                richTextBox2.Text += sr.ReadToEnd();	//讀取所有文字內容
                sr.Close();

                bt_script_load.Visible = false;
            }
            else
            {
                richTextBox1.Text += "未選取檔案\n";
            }
            bt_script_load.Text = "Load";
        }

