        private void sensor_data_bit_change(object sender, EventArgs e)
        {
            //richTextBox1.Text += "sensor_data_bit_change\n";
            int value = 0;
            if (b7.Checked == true)
                value |= (1 << 7);
            if (b6.Checked == true)
                value |= (1 << 6);
            if (b5.Checked == true)
                value |= (1 << 5);
            if (b4.Checked == true)
                value |= (1 << 4);
            if (b3.Checked == true)
                value |= (1 << 3);
            if (b2.Checked == true)
                value |= (1 << 2);
            if (b1.Checked == true)
                value |= (1 << 1);
            if (b0.Checked == true)
                value |= (1 << 0);
            //richTextBox1.Text += "value = 0x " + value.ToString("X2") + " = " + value.ToString() + "\n";
            tb_3a.Text = value.ToString("X2");
            tb_4a.Text = value.ToString();
        }

        void show_hex2bit(int value)
        {
            //richTextBox1.Text += "show_hex2bit\n";
            if (((value >> 7) & 0x01) == 0x01)
                b7.Checked = true;
            else
                b7.Checked = false;
            if (((value >> 6) & 0x01) == 0x01)
                b6.Checked = true;
            else
                b6.Checked = false;
            if (((value >> 5) & 0x01) == 0x01)
                b5.Checked = true;
            else
                b5.Checked = false;
            if (((value >> 4) & 0x01) == 0x01)
                b4.Checked = true;
            else
                b4.Checked = false;
            if (((value >> 3) & 0x01) == 0x01)
                b3.Checked = true;
            else
                b3.Checked = false;
            if (((value >> 2) & 0x01) == 0x01)
                b2.Checked = true;
            else
                b2.Checked = false;
            if (((value >> 1) & 0x01) == 0x01)
                b1.Checked = true;
            else
                b1.Checked = false;
            if (((value >> 0) & 0x01) == 0x01)
                b0.Checked = true;
            else
                b0.Checked = false;
        }

