        private void bt_saturation_Click(object sender, EventArgs e)
        {
            richTextBox1.Text += "Setup saturation\n";

            if (get_comport_status() == false)
                return;

            /*
            byte SendData;
            DongleAddr_h = 0x58;
            DongleAddr_l = 0x03;
            SendData = 0x20;
            Send_IMS_Data(0xA0, DongleAddr_h, DongleAddr_l, SendData);

            DongleAddr_h = 0x58;
            DongleAddr_l = 0x04;
            SendData = 0x14;
            Send_IMS_Data(0xA0, DongleAddr_h, DongleAddr_l, SendData);
            */

            int sat = (int)numericUpDown_saturation.Value;

            richTextBox1.Text += "Setup saturation = " + sat.ToString() + "\n";

            byte SendData;
            DongleAddr_h = 0x58;
            DongleAddr_l = 0x03;
            SendData = (byte)sat;
            Send_IMS_Data(0xA0, DongleAddr_h, DongleAddr_l, SendData);

            sat = sat * 7 / 10;
            DongleAddr_h = 0x58;
            DongleAddr_l = 0x04;
            SendData = (byte)sat;
            Send_IMS_Data(0xA0, DongleAddr_h, DongleAddr_l, SendData);

        }

