        private void timer_stage5_Tick(object sender, EventArgs e)
        {
            if (flag_doing_writing_data == true)
            {
                richTextBox1.Text += "正在存檔, 忽略\n";
                return;
            }

            ccc++;
            if ((ccc % 4) == 0)
                lb_main_mesg5.Text = "等待輸入資料 \\";
            else if ((ccc % 4) == 1)
                lb_main_mesg5.Text = "等待輸入資料 |";
            else if ((ccc % 4) == 2)
                lb_main_mesg5.Text = "等待輸入資料 /";
            else
                lb_main_mesg5.Text = "等待輸入資料 -";

            if ((timer_cnt++ % 10) == 0)
            {
                richTextBox1.Text += "五";
                if (this.tb_wait_product_data.Focused == false)
                {
                    this.tb_wait_product_data.Focus();
                    richTextBox1.Text += "F5";
                }
            }

            if (flag_network_disk_status == false)
            {
                tb_wait_product_data.Clear();

                show_main_message1("無法連上網路磁碟機", S_FALSE, 30);
                show_main_message2("無法連上網路磁碟機", S_FALSE, 30);
                show_main_message3("無法連上網路磁碟機", S_FALSE, 30);
            }

            int len;
            len = tb_wait_product_data.Text.Length;

            if (len > 50)   //太長, 直接放棄
            {
                tb_wait_product_data.Clear();
                //richTextBox1.Text += "X1";
                return;
            }
            else if (len > 5)    //檢查是否換行
            {
                if ((tb_wait_product_data.Text[len - 2] == 0x0D) || (tb_wait_product_data.Text[len - 1] == 0x0A))
                {
                    tb_wait_product_data.Text = tb_wait_product_data.Text.Trim();
                    //richTextBox1.Text += "OK";
                }
                else
                {
                    //richTextBox1.Text += "X2";
                    return;
                }
            }
            else    //太短  留著累計
            {
                //richTextBox1.Text += "X3";
                return;
            }

            int i;
            if (tb_wait_product_data.Text.Length > 0)
            {
                bool flag_incorrect_data = false;
                if (tb_wait_product_data.Text.Length == 12) //支持1英11數
                {
                    //長度12 => 第一段
                    for (i = 1; i < tb_wait_product_data.Text.Length; i++)
                    {
                        if ((tb_wait_product_data.Text[i] < '0') || (tb_wait_product_data.Text[i] > '9'))
                        {
                            flag_incorrect_data = true;
                            richTextBox1.Text += "資料p1格式不正確\n";
                            tb_wait_product_data.Text = "";
                            tb_product1.Clear();
                            tb_product1.BackColor = Color.Pink;
                            break;
                        }
                    }
                    if (flag_incorrect_data == false)
                    {
                        //檢查英文字母的正確性
                        if ((tb_wait_product_data.Text[0] < 'A') || (tb_wait_product_data.Text[0] > 'Z'))
                        {
                            flag_incorrect_data = true;
                            richTextBox1.Text += "資料長度正確, 數字正確, 但是英文字錯誤, 清除\n";
                            tb_wait_product_data.Text = "";
                            tb_product1.Clear();
                            tb_product1.BackColor = Color.Pink;
                        }
                    }

                    if (flag_incorrect_data == false)
                    {
                        richTextBox1.Text += "取得資料1 : " + tb_wait_product_data.Text + "\n";
                        tb_product1.Text = tb_wait_product_data.Text;
                        tb_product1.BackColor = Color.White;
                        tb_wait_product_data.Text = "";
                        if ((flag_ok_data1 == false) && (flag_ok_data2 == false) && (flag_ok_data3 == false))
                        {
                            panel4.BackgroundImage = null;
                            g3.Clear(BackColor);
                        }
                        flag_ok_data1 = true;
                        check_export_data();
                    }
                }
                else if (tb_wait_product_data.Text.Length == 13) //支持 1英7數1英4數
                {
                    //長度13 => 第一段
                    for (i = 1; i < tb_wait_product_data.Text.Length; i++)
                    {
                        if (i == 8)
                            continue;
                        if ((tb_wait_product_data.Text[i] < '0') || (tb_wait_product_data.Text[i] > '9'))
                        {
                            flag_incorrect_data = true;
                            richTextBox1.Text += "資料p1格式不正確\n";
                            tb_wait_product_data.Text = "";
                            tb_product1.Clear();
                            tb_product1.BackColor = Color.Pink;
                            break;
                        }
                    }
                    if (flag_incorrect_data == false)
                    {
                        //檢查英文字母的正確性
                        if ((tb_wait_product_data.Text[0] < 'A') || (tb_wait_product_data.Text[0] > 'Z'))
                        {
                            flag_incorrect_data = true;
                            richTextBox1.Text += "資料長度正確, 數字正確, 但是英文字錯誤a, 清除\n";
                            tb_wait_product_data.Text = "";
                            tb_product1.Clear();
                            tb_product1.BackColor = Color.Pink;
                        }
                        if ((tb_wait_product_data.Text[8] < 'A') || (tb_wait_product_data.Text[8] > 'Z'))
                        {
                            flag_incorrect_data = true;
                            richTextBox1.Text += "資料長度正確, 數字正確, 但是英文字錯誤b, 清除\n";
                            tb_wait_product_data.Text = "";
                            tb_product1.Clear();
                            tb_product1.BackColor = Color.Pink;
                        }
                    }

                    if (flag_incorrect_data == false)
                    {
                        richTextBox1.Text += "取得資料1 : " + tb_wait_product_data.Text + "\n";
                        tb_product1.Text = tb_wait_product_data.Text;
                        tb_product1.BackColor = Color.White;
                        tb_wait_product_data.Text = "";
                        if ((flag_ok_data1 == false) && (flag_ok_data2 == false) && (flag_ok_data3 == false))
                        {
                            panel4.BackgroundImage = null;
                            g3.Clear(BackColor);
                        }
                        flag_ok_data1 = true;
                        check_export_data();
                    }
                }
                else if (tb_wait_product_data.Text.Length == 11)    //因應重工 要能支持11數
                {
                    //長度11 => 第一段
                    for (i = 0; i < tb_wait_product_data.Text.Length; i++)
                    {
                        if ((tb_wait_product_data.Text[i] < '0') || (tb_wait_product_data.Text[i] > '9'))
                        {
                            flag_incorrect_data = true;
                            richTextBox1.Text += "資料p1格式不正確\n";
                            tb_wait_product_data.Text = "";
                            tb_product1.Clear();
                            tb_product1.BackColor = Color.Pink;
                            break;
                        }
                    }

                    if (flag_incorrect_data == false)
                    {
                        richTextBox1.Text += "取得資料1 : " + tb_wait_product_data.Text + "\n";
                        tb_product1.Text = tb_wait_product_data.Text;
                        tb_product1.BackColor = Color.White;
                        tb_wait_product_data.Text = "";
                        if ((flag_ok_data1 == false) && (flag_ok_data2 == false) && (flag_ok_data3 == false))
                        {
                            panel4.BackgroundImage = null;
                            g3.Clear(BackColor);
                        }
                        flag_ok_data1 = true;
                        check_export_data();
                    }
                }
                else if ((tb_wait_product_data.Text.Length == 38) || (tb_wait_product_data.Text.Length == 41))
                {
                    //長度38 41 => 第二段
                    for (i = 0; i < tb_wait_product_data.Text.Length; i++)
                    {
                        if ((tb_wait_product_data.Text.Length == 41) && ((i == 26) || (i == 36))) //41碼, 第26碼 第36碼 要英文
                        {
                            if (((tb_wait_product_data.Text[i] >= 'A') && (tb_wait_product_data.Text[i] <= 'Z')) || ((tb_wait_product_data.Text[i] >= 'a') && (tb_wait_product_data.Text[i] <= 'z')))
                            {
                                flag_incorrect_data = false;
                            }
                            else
                            {
                                flag_incorrect_data = true;
                                richTextBox1.Text += "資料p2格式不正確a1\n";
                                tb_wait_product_data.Text = "";
                                tb_product2.Clear();
                                tb_product2.BackColor = Color.Pink;
                            }
                        }
                        else if ((tb_wait_product_data.Text[i] < '0') || (tb_wait_product_data.Text[i] > '9'))
                        {
                            flag_incorrect_data = true;
                            richTextBox1.Text += "資料p2格式不正確a2\n";
                            tb_wait_product_data.Text = "";
                            tb_product2.Clear();
                            tb_product2.BackColor = Color.Pink;
                            break;
                        }
                    }

                    if (flag_incorrect_data == false)
                    {
                        richTextBox1.Text += "取得資料2 : " + tb_wait_product_data.Text + "\n";
                        tb_product2.Text = tb_wait_product_data.Text;
                        tb_product2.BackColor = Color.White;
                        tb_wait_product_data.Text = "";
                        if ((flag_ok_data1 == false) && (flag_ok_data2 == false) && (flag_ok_data3 == false))
                        {
                            panel4.BackgroundImage = null;
                            g3.Clear(BackColor);
                        }
                        flag_ok_data2 = true;
                        check_export_data();
                    }
                }
                else if (tb_wait_product_data.Text.Length == 39)
                {
                    //第3段 長度39碼 全數

                    //檢查是否符合第3段資料 長度40碼 英文在26
                    for (i = 0; i < tb_wait_product_data.Text.Length; i++)
                    {
                        if ((tb_wait_product_data.Text[i] < '0') || (tb_wait_product_data.Text[i] > '9'))
                        {
                            flag_incorrect_data = true;
                            richTextBox1.Text += "資料p2格式不正確a2\n";
                            break;
                        }
                    }

                    if (flag_incorrect_data == false)
                    {
                        richTextBox1.Text += "取得資料3 : " + tb_wait_product_data.Text + "\n";
                        tb_product3.Text = tb_wait_product_data.Text;
                        tb_product3.BackColor = Color.White;
                        tb_wait_product_data.Text = "";
                        if ((flag_ok_data1 == false) && (flag_ok_data2 == false) && (flag_ok_data3 == false))
                        {
                            panel4.BackgroundImage = null;
                            g3.Clear(BackColor);
                        }
                        flag_ok_data3 = true;
                        check_export_data();
                    }
                }
                else if (tb_wait_product_data.Text.Length == 40) //可能是第2段, 可能是第3段
                {
                    //第3段 長度40碼 英文在26
                    //第2段 長度40碼 英文在35

                    //檢查是否符合第3段資料 長度40碼 英文在26
                    for (i = 0; i < tb_wait_product_data.Text.Length; i++)
                    {
                        if (i == 26)  //40碼, 第26碼 要英文
                        {
                            if (((tb_wait_product_data.Text[i] >= 'A') && (tb_wait_product_data.Text[i] <= 'Z')) || ((tb_wait_product_data.Text[i] >= 'a') && (tb_wait_product_data.Text[i] <= 'z')))
                            {
                                flag_incorrect_data = false;
                            }
                            else
                            {
                                flag_incorrect_data = true;
                                richTextBox1.Text += "資料p3格式不正確a1\n";
                                break;
                            }
                        }
                        else if ((tb_wait_product_data.Text[i] < '0') || (tb_wait_product_data.Text[i] > '9'))
                        {
                            flag_incorrect_data = true;
                            richTextBox1.Text += "資料p2格式不正確a2\n";
                            break;
                        }
                    }

                    if (flag_incorrect_data == false)
                    {
                        richTextBox1.Text += "取得資料3 : " + tb_wait_product_data.Text + "\n";
                        tb_product3.Text = tb_wait_product_data.Text;
                        tb_product3.BackColor = Color.White;
                        tb_wait_product_data.Text = "";
                        if ((flag_ok_data1 == false) && (flag_ok_data2 == false) && (flag_ok_data3 == false))
                        {
                            panel4.BackgroundImage = null;
                            g3.Clear(BackColor);
                        }
                        flag_ok_data3 = true;
                        check_export_data();
                    }
                    else
                    {
                        //檢查是否符合第2段資料 長度40碼 英文在35
                        for (i = 0; i < tb_wait_product_data.Text.Length; i++)
                        {
                            if ((tb_wait_product_data.Text.Length == 40) && ((i == 35))) //40碼, 第35碼 要英文 => 第2段
                            {
                                if (((tb_wait_product_data.Text[i] >= 'A') && (tb_wait_product_data.Text[i] <= 'Z')) || ((tb_wait_product_data.Text[i] >= 'a') && (tb_wait_product_data.Text[i] <= 'z')))
                                {
                                    flag_incorrect_data = false;
                                }
                                else
                                {
                                    flag_incorrect_data = true;

                                    richTextBox1.Text += "資料p2格式不正確a1\n";
                                }
                            }
                            else if ((tb_wait_product_data.Text[i] < '0') || (tb_wait_product_data.Text[i] > '9'))
                            {
                                flag_incorrect_data = true;

                                richTextBox1.Text += "資料p2格式不正確a2\n";
                                break;
                            }
                        }

                        if (flag_incorrect_data == false)
                        {
                            richTextBox1.Text += "取得資料2 : " + tb_wait_product_data.Text + "\n";
                            tb_product2.Text = tb_wait_product_data.Text;
                            tb_product2.BackColor = Color.White;
                            tb_wait_product_data.Text = "";
                            if ((flag_ok_data1 == false) && (flag_ok_data2 == false) && (flag_ok_data3 == false))
                            {
                                panel4.BackgroundImage = null;
                                g3.Clear(BackColor);
                            }
                            flag_ok_data2 = true;
                            check_export_data();
                        }
                        else
                        {
                            tb_wait_product_data.Text = "";
                        }
                    }
                }
                else if (tb_wait_product_data.Text.Length == 20)
                {
                    //長度20 => 第三段
                    for (i = 0; i < tb_wait_product_data.Text.Length; i++)
                    {
                        if ((i == 6) || (i == 15))
                        {
                            if (tb_wait_product_data.Text[i] != '-')
                            {
                                flag_incorrect_data = true;
                                richTextBox1.Text += "資料p3格式不正確a\n";
                                tb_wait_product_data.Text = "";
                                tb_product3.Clear();
                                tb_product3.BackColor = Color.Pink;
                            }
                        }
                        else if (((tb_wait_product_data.Text[i] < '0') || (tb_wait_product_data.Text[i] > '9')) && (i != 7))
                        {
                            flag_incorrect_data = true;
                            richTextBox1.Text += "資料p3格式不正確b\n";
                            tb_wait_product_data.Text = "";
                            tb_product3.Clear();
                            tb_product3.BackColor = Color.Pink;
                            break;
                        }
                    }

                    if (flag_incorrect_data == false)
                    {
                        richTextBox1.Text += "取得資料3 : " + tb_wait_product_data.Text + "\n";
                        tb_product3.Text = tb_wait_product_data.Text;
                        tb_product3.BackColor = Color.White;
                        tb_wait_product_data.Text = "";
                        if ((flag_ok_data1 == false) && (flag_ok_data2 == false) && (flag_ok_data3 == false))
                        {
                            panel4.BackgroundImage = null;
                            g3.Clear(BackColor);
                        }
                        flag_ok_data3 = true;
                        check_export_data();
                    }
                }
                else
                {
                    flag_incorrect_data = true;
                    richTextBox1.Text += "有資料, 但是長度錯誤, 一律清除a\n";
                    tb_wait_product_data.Text = "";
                }
            }
        }

