        int check_network_disk()
        {
            if (flag_enaglb_automation == true)
            {
                //自動化, 偽連上網路磁碟機
                flag_network_disk_status = true;
                return S_OK;
            }

            if (flag_operation_mode == MODE_RELEASE_STAGE20)
            {
                //檢查相機, 偽連上網路磁碟機
                flag_network_disk_status = true;
                return S_OK;
            }

            richTextBox1.Text += "檢查網路磁碟機\n";
            string PathM = "M:\\";  //M槽放圖
            string PathN = "N:\\";  //N槽放CSV檔

            if ((flag_operation_mode != MODE_RELEASE_STAGE1C) && (flag_operation_mode != MODE_RELEASE_STAGE2) && (flag_operation_mode != MODE_RELEASE_STAGE5)
                && (flag_operation_mode != MODE_RELEASE_STAGE6) && (flag_operation_mode != MODE_RELEASE_STAGE7) && (flag_operation_mode != MODE_RELEASE_STAGE8)
                && (flag_operation_mode != MODE_RELEASE_STAGE9) && (flag_operation_mode != MODE_RELEASE_STAGE11) && (flag_operation_mode != MODE_RELEASE_STAGE12)
                && (Directory.Exists(PathM) == false))     //確認資料夾是否存在
            {
                show_main_message1("無法連上 " + PathM, S_FALSE, 30);
                show_main_message2("無法連上 " + PathM, S_FALSE, 30);
                show_main_message3("無法連上 " + PathM, S_FALSE, 30);
                flag_network_disk_status = false;
            }
            else if (Directory.Exists(PathN) == false)     //確認資料夾是否存在
            {
                show_main_message1("無法連上 " + PathN, S_FALSE, 30);
                show_main_message2("無法連上 " + PathN, S_FALSE, 30);
                show_main_message3("無法連上 " + PathN, S_FALSE, 30);
                flag_network_disk_status = false;
            }
            else
            {
                show_main_message1("已連上 " + PathM + ", " + PathN, S_OK, 10);
                //show_main_message2("已連上 " + PathM + ", " + PathN, S_OK, 10);
                show_main_message3("已連上 " + PathM + ", " + PathN, S_OK, 10);
                flag_network_disk_status = true;
                richTextBox1.Text += "已連上 " + PathM + "\n";
                richTextBox1.Text += "已連上 " + PathN + "\n";
            }

            if (flag_network_disk_status == true)
                return S_OK;
            else
                return S_FALSE;
        }

        private void button49_Click(object sender, EventArgs e)
