        int check_sale3_data()
        {
            tb_sale3.Text = tb_sale3.Text.Trim();
            if (tb_sale3.Text.Length > 0)
            {
                //richTextBox1.Text += "len = " + tb_sale3.Text.Length.ToString() + "\n";
                int i;
                bool flag_incorrect_data = false;
                /*
                if (tb_sale3.Text.Length == 11)
                {
                    for (i = 0; i < tb_sale3.Text.Length; i++)
                    {
                        if ((tb_sale3.Text[i] < '0') || (tb_sale3.Text[i] > '9'))
                        {
                            flag_incorrect_data = true;
                            richTextBox1.Text += "序號格式不正確d\n";
                            tb_sale3.Clear();
                            tb_sale3.BackColor = Color.Pink;
                        }
                    }

                    if (flag_incorrect_data == false)
                    {
                        richTextBox1.Text += "取得序號 : " + tb_sale3.Text + "\n";
                        tb_sale3.BackColor = Color.Pink;
                        flag_ok_data3 = true;
                        //check_export_data();
                    }
                }
                */
                if ((tb_sale3.Text.Length == 39) || (tb_sale3.Text.Length == 40) || (tb_sale3.Text.Length == 41) || (tb_sale3.Text.Length == 42))
                {
                    if (tb_sale3.Text.Length == 39)         //all numbers　ex : 010000000000000017221202102012002210015
                    {
                        for (i = 0; i < tb_sale3.Text.Length; i++)
                        {
                            if ((tb_sale3.Text[i] < '0') || (tb_sale3.Text[i] > '9'))
                            {
                                flag_incorrect_data = true;
                                richTextBox1.Text += "_39資料格式不正確, 資料 : " + tb_sale3.Text + "\n";
                                tb_sale3.Clear();
                                tb_sale3.BackColor = Color.Pink;
                            }
                        }
                    }
                    else if (tb_sale3.Text.Length == 40)          //len = 40  ex : 0100000000000000 17221202 10N2012002 210015  => 01047198807690181727052810200400221A0050
                    {
                        for (i = 0; i < tb_sale3.Text.Length; i++)
                        {
                            if ((i != 35) || (i != 35))     //position 26/35 contains non-numbers
                            {
                                if ((tb_sale3.Text[i] < '0') || (tb_sale3.Text[i] > '9'))
                                {
                                    flag_incorrect_data = true;
                                    richTextBox1.Text += "_40資料格式不正確, 資料 : " + tb_sale3.Text + "\n";
                                    tb_sale3.Clear();
                                    tb_sale3.BackColor = Color.Pink;
                                }
                            }
                        }
                    }
                    else if (tb_sale3.Text.Length == 41)          //len = 41  ex : 0100000000000000 17230721 10N2106002 21A0264
                    {
                        for (i = 0; i < tb_sale3.Text.Length; i++)
                        {
                            if ((i != 26) && (i != 36))     //position 26, 36 contains non-numbers
                            {
                                if ((tb_sale3.Text[i] < '0') || (tb_sale3.Text[i] > '9'))
                                {
                                    flag_incorrect_data = true;
                                    richTextBox1.Text += "_41資料格式不正確, 資料 : " + tb_sale3.Text + "\n";
                                    tb_sale3.Clear();
                                    tb_sale3.BackColor = Color.Pink;
                                }
                            }
                        }
                    }
                    else if (tb_sale3.Text.Length == 42)          //len = 42  ex : 0100000000000000 17230721 10N2106002 21A0264 ?
                    {
                        for (i = 0; i < tb_sale3.Text.Length; i++)
                        {
                            if ((i != 26) && (i != 36))     //position 26, 36 contains non-numbers
                            {
                                if ((tb_sale3.Text[i] < '0') || (tb_sale3.Text[i] > '9'))
                                {
                                    flag_incorrect_data = true;
                                    richTextBox1.Text += "_42資料格式不正確, 資料 : " + tb_sale3.Text + "\n";
                                    tb_sale3.Clear();
                                    tb_sale3.BackColor = Color.Pink;
                                }
                            }
                        }
                    }
                    else
                    {
                        flag_incorrect_data = true;
                    }

                    if (flag_incorrect_data == false)
                    {
                        richTextBox1.Text += "取得序號 : " + tb_sale3.Text + "\n";
                        tb_sale3.BackColor = Color.Pink;
                        flag_ok_data3 = true;
                        //check_export_data();
                    }
                }
                else if (tb_sale3.Text.Length == 20)        //改成只援20碼 多一碼N
                {
                    for (i = 0; i < tb_sale3.Text.Length; i++)
                    {
                        if ((i == 6) || (i == 15))
                        {
                            if (tb_sale3.Text[i] != '-')
                            {
                                flag_incorrect_data = true;
                                richTextBox1.Text += "箱號格式不正確a\n";
                                tb_sale3.Clear();
                                tb_sale3.BackColor = Color.Pink;
                            }
                        }
                        else if ((i != 7) && ((tb_sale3.Text[i] < '0') || (tb_sale3.Text[i] > '9')))
                        {
                            flag_incorrect_data = true;
                            richTextBox1.Text += "箱號格式不正確b\n";
                            tb_sale3.Clear();
                            tb_sale3.BackColor = Color.Pink;
                        }
                    }

                    if (flag_incorrect_data == false)
                    {
                        richTextBox1.Text += "取得箱號 : " + tb_sale3.Text + "\n";
                        tb_sale3.BackColor = Color.Pink;
                        flag_ok_data3 = true;
                        //check_export_data();
                    }
                }
                else if (tb_sale3.Text.Length == 12)        //改成只援12碼 ex : R21090010022   1英11數
                {
                    for (i = 0; i < tb_sale3.Text.Length; i++)
                    {
                        if ((i != 0) && ((tb_sale3.Text[i] < '0') || (tb_sale3.Text[i] > '9')))
                        {
                            if (tb_sale3.Text[i] != '-')
                            {
                                flag_incorrect_data = true;
                                richTextBox1.Text += "箱號格式不正確a\n";
                                tb_sale3.Clear();
                                tb_sale3.BackColor = Color.Pink;
                            }
                        }
                    }

                    if (flag_incorrect_data == false)
                    {
                        richTextBox1.Text += "取得箱號 : " + tb_sale3.Text + "\n";
                        tb_sale3.BackColor = Color.Pink;
                        flag_ok_data3 = true;
                        //check_export_data();
                    }
                }
                else
                {
                    flag_incorrect_data = true;
                    richTextBox1.Text += "有資料, 但是長度錯誤, 一律清除f, 長度 : " + tb_sale3.Text.Length.ToString() + "\n";
                    richTextBox1.Text += "資料 : " + tb_sale3.Text + "\n";
                    tb_sale3.Clear();
                    tb_sale3.BackColor = Color.Pink;
                }

                if (flag_incorrect_data == false)
                    return S_OK;
                else
                    return S_FALSE;
            }
            else
                return S_FALSE;
        }

        private void bt_awb_break_Click(object sender, EventArgs e)
        {
            if (bt_awb_break.Text == "中斷")
            {
                bt_awb_break.Text = "確認";
                tb_awb_mesg.Text = "色彩校正中斷";
                richTextBox1.Text += "AWB 中斷 AWB 中斷 AWB 中斷\n";
                flag_break_doing_awb = true;
                flag_awb_break = true;
                flag_awb_manually_interrupt = true;
            }
            else if (bt_awb_break.Text == "確認")
            {
                richTextBox1.Text += "AWB 中斷 確認\n";
                bt_awb_break.Text = "中斷";
                //tb_awb_mesg.Text = "";
