            }
            catch (Exception ex)
            {
                richTextBox1.Text += "xxx錯誤訊息e36 : " + ex.Message + "\n";
                GC.Collect();       //回收資源
                flag_do_find_awb_location = false;
                return S_FALSE;
            }

            ww = awb_block;
            hh = awb_block;
