                    flag_incorrect_data = true;
                }
                else if ((tb_sn_opal.Text.Length == 9) || (tb_sn_opal.Text.Length == 10))//10碼 2英8數 或 10數
                {
                    //檢查後8碼為數字
                    for (i = 2; i < tb_sn_opal.Text.Length; i++)
                    {
                        if ((tb_sn_opal.Text[i] < '0') || (tb_sn_opal.Text[i] > '9'))
