        void measure_brightness_one_frame()
        {
            string mesg = "量整張畫面亮度\n";
            double result = -1;

            /*
            int ww = 10;
            int hh = 10;
            int x_st;
            int i;

            for (i = 0; i < 8; i++)
            {
                x_st = 80 * i + 80 / 2 - ww / 2;
                result = measure_brightness_one_frame0(x_st, 100, ww, hh);
                richTextBox1.Text += "result : " + result.ToString() + "\n";

            }
            */

            result = measure_brightness_one_frame0(640 / 4, 480 / 4, 640 / 2, 480 / 2);
            richTextBox1.Text += "中間1/4張平均 : result : " + result.ToString("F4") + "\n";
            brightness_result_quarter = result;
            mesg += "中間1/4張平均 : " + result.ToString("F4") + "\n";

            result = measure_brightness_one_frame0(0, 0, 640, 480);
            richTextBox1.Text += "整張平均 : result : " + result.ToString("F4") + "\n";
            brightness_result_full = result;
            mesg += "整張平均 : " + result.ToString("F4");

            show_main_message0(mesg, S_OK, 50);
        }

        double measure_brightness_one_frame0(int x_st, int y_st, int ww, int hh)
        {
            if ((ww <= 0) || (hh <= 0))
            {
                richTextBox1.Text += "量測點數 ww = " + ww.ToString() + ", hh = " + hh.ToString() + " 不合法\n";
                return -1;
            }
            flag_do_find_awb_location = true;
            int w;
            int h;
            int i;
            int j;
            Color p;
            Bitmap bm2 = null;
            double y_total = 0;
            int result = -1;

            tb_awb_mesg.Text = "量測亮度";

            try
            {
                //pictureBox1.Image = (Bitmap)eventArgs.Frame.Clone();
                //bm2 = bm;
                bm2 = (Bitmap)bm.Clone();
                //pictureBox1.Image = bm;
            }
            catch (Exception ex)
            {
                richTextBox1.Text += "xxx錯誤訊息e51 : " + ex.Message + "\n";
                GC.Collect();       //回收資源
                flag_do_find_awb_location = false;
                return result;
            }

            try
            {
                ga = Graphics.FromImage(bm2);
            }
            catch (Exception ex)
            {
                richTextBox1.Text += "xxx錯誤訊息e52 : " + ex.Message + "\n";
                GC.Collect();       //回收資源
                flag_do_find_awb_location = false;
                return result;
            }

            try
            {
                w = bm2.Width;
                h = bm2.Height;
            }
            catch (Exception ex)
            {
                richTextBox1.Text += "xxx錯誤訊息e53 : " + ex.Message + "\n";
                GC.Collect();       //回收資源
                flag_do_find_awb_location = false;
                return result;
            }

            if (x_st < 0)
                x_st = 0;
            if (y_st < 0)
                y_st = 0;
            if ((x_st + ww) > w)
                x_st = w - ww;
            if ((y_st + hh) > h)
                y_st = h - hh;

            //richTextBox1.Text += "量測起點 x_st = " + x_st.ToString() + ", y_st = " + y_st.ToString() + "\n";
            //richTextBox1.Text += "量測範圍 ww = " + ww.ToString() + ", hh = " + hh.ToString() + "\n";

            for (j = y_st; j < (y_st + hh); j++)
            {
                for (i = x_st; i < (x_st + ww); i++)
                {
                    p = bm2.GetPixel(i, j);
                    //bm2.SetPixel(i, j, Color.FromArgb(255, 0, 0));
                    RGB pp = new RGB(p.R, p.G, p.B);
                    YUV yyy = new YUV();
                    yyy = RGBToYUV(pp);
                    y_total += yyy.Y;
                }
            }
            ga.DrawRectangle(new Pen(Color.Red, 1), x_st - 2, y_st - 2, ww + 4, hh + 4);

            //richTextBox1.Text += "y_total = " + y_total.ToString() + "\n";
            //richTextBox1.Text += "y_avg = " + (y_total / (ww * hh)).ToString() + "\n\n";

            tb_awb_mesg.Text = "亮度: " + (y_total / (ww * hh)).ToString("F2");

            GC.Collect();       //回收資源
            //pictureBox1.Image = bm2;

            delay(10);
            flag_do_find_awb_location = false;
            return y_total / (ww * hh);
        }

        void find_series_max_min()
        {
            if (((flag_operation_mode == MODE_RELEASE_STAGE0) || (flag_operation_mode == MODE_RELEASE_STAGE2)) && (flag_use_chart1 == true))
            {
                int count = series_r.Points.Count;
                int i;
                average_RGB_max = 0;
                average_RGB_min = 256;

                for (i = 0; i < count; i++)
                {
                    /*
                    richTextBox1.Text += "x["+i.ToString()+"] = " + series_r.Points[i].XValue.ToString() + "\t";
                    richTextBox1.Text += "y_r[" + i.ToString() + "] = " + series_r.Points[i].YValues[0].ToString() + "\t";
                    richTextBox1.Text += "y_g[" + i.ToString() + "] = " + series_g.Points[i].YValues[0].ToString() + "\t";
                    richTextBox1.Text += "y_b[" + i.ToString() + "] = " + series_b.Points[i].YValues[0].ToString() + "\n";
                    */

                    if (series_r.Points[i].YValues[0] > average_RGB_max)
                        average_RGB_max = series_r.Points[i].YValues[0];
                    if (series_g.Points[i].YValues[0] > average_RGB_max)
                        average_RGB_max = series_g.Points[i].YValues[0];
                    if (series_b.Points[i].YValues[0] > average_RGB_max)
                        average_RGB_max = series_b.Points[i].YValues[0];

                    if (series_r.Points[i].YValues[0] < average_RGB_min)
                        average_RGB_min = series_r.Points[i].YValues[0];
                    if (series_g.Points[i].YValues[0] < average_RGB_min)
                        average_RGB_min = series_g.Points[i].YValues[0];
                    if (series_b.Points[i].YValues[0] < average_RGB_min)
                        average_RGB_min = series_b.Points[i].YValues[0];
                }
                //richTextBox1.Text += "Max = " + average_RGB_max.ToString() + ", min = " + average_RGB_min.ToString() + "\n";
            }
        }

