        private void bt_debug3_Click(object sender, EventArgs e)
        {
            show_main_message0("debug3 : 測試comport連線 300次", S_OK, 30);

            int i = 0;
            int ret;

            connect_comport_cnt_max = 0;
            richTextBox1.Clear();
            richTextBox1.Text += "測試開始\t";
            richTextBox1.Text += "時間 : " + DateTime.Now.ToString() + "\n";
            if (flag_comport_ok == true)
            {
                serialPort2.Close();
                this.BackColor = Color.Yellow;
                bt_comport_connect1b.Enabled = true;
                bt_comport_disconnect1b.Enabled = false;
                flag_comport_ok = false;
                show_main_message1("COM未連線", S_FALSE, 100);
                pictureBox_comport1b.Image = iMS_Link.Properties.Resources.x;
                toolTip1.SetToolTip(pictureBox_comport1b, "COM未連線");
            }

            for (i = 0; i < total_test_count; i++)
            {
                richTextBox1.Text += "\n第 " + (i + 1).ToString() + " 次\n";
                show_main_message1(i.ToString(), S_FALSE, 300);

                ret = try_connect_comport();
                if (ret == S_OK)
                {
                    richTextBox1.Text += "已連上IMS EGD System\n";
                    show_main_message1("COM已連線", S_OK, 30);
                    pictureBox_comport1b.Image = iMS_Link.Properties.Resources.comport;
                    toolTip1.SetToolTip(pictureBox_comport1b, "COM已連線");

                    //計算serialPort2中有多少位元組 
                    BytesToRead = serialPort2.BytesToRead;

                    if (BytesToRead > 0)
                    {
                        //開啟程式時, 把所有serialPort的資料讀出來, 並丟棄之
                        serialPort2.DiscardInBuffer();  //丟棄UART buffer內的資料
                    }
                }
                else
                {
                    richTextBox1.Text += "COM未連線\n";
                    this.BackColor = Color.Pink;
                    show_main_message1("COM未連線", S_FALSE, 100);
                    pictureBox_comport1b.Image = iMS_Link.Properties.Resources.x;
                    toolTip1.SetToolTip(pictureBox_comport1b, "COM未連線");

                    serialPort2.Close();
                    this.BackColor = Color.Yellow;
                    bt_comport_connect1b.Enabled = true;
                    button89.Enabled = true;
                    bt_comport_disconnect1b.Enabled = false;
                    button90.Enabled = false;
                    flag_comport_ok = false;

                    break;
                }
                delay(1000);

                if (flag_comport_ok == true)
                {
                    serialPort2.Close();
                    this.BackColor = Color.Yellow;
                    bt_comport_connect1b.Enabled = true;
                    bt_comport_disconnect1b.Enabled = false;
                    flag_comport_ok = false;
                    show_main_message1("COM未連線", S_FALSE, 100);
                    pictureBox_comport1b.Image = iMS_Link.Properties.Resources.x;
                    toolTip1.SetToolTip(pictureBox_comport1b, "COM未連線");
                }

                if (i == (total_test_count - 1))
                {
                    show_main_message1("測試完成", S_OK, 10000);
                    richTextBox1.Text += "\n測試結束\t";
                    richTextBox1.Text += "時間 : " + DateTime.Now.ToString() + "\n";
                }
                delay(100);
            }
        }

