        void measure_picture()
        {
            if (bm == null)
                return;

            flag_do_find_awb_location = true;

            int ww;
            int hh;
            int x_st;
            int y_st;

            int w;
            int h;
            int i;
            int j;
            Color p;
            Bitmap bm2 = null;

            double total_R = 0;
            double total_G = 0;
            double total_B = 0;
            double total_Y = 0;

