        private void pictureBox3_MouseMove(object sender, MouseEventArgs e)
        {
            if (flag_pictureBox3_mouse_down == true)
            {
                //richTextBox1.Text += "Up : (" + e.X.ToString() + ", " + e.Y.ToString() + ")\n";
                int dx = e.X - pictureBox3_position_x_old;
