        int check_camera_sensor_fail_cnt = 0;
        int check_camera_status_fail_cnt = 0;
        int get_camera_status()
        {
            bt_camera_info_read.BackColor = Color.Red;
            button8.BackColor = Color.Red;
            panel_camera_status1.BackgroundImage = null;
            panel_camera_status2.BackgroundImage = null;
            panel_camera_status3.BackgroundImage = null;
            panel_camera_status4.BackgroundImage = null;
            panel_camera_status5.BackgroundImage = null;
            panel_camera_status6.BackgroundImage = null;

            serialPort2.DiscardInBuffer();  //丟棄UART buffer內的資料

            //開始檢查相機連線
            g_conn_status = CAMERA_UNKNOWN;
            Send_IMS_Data(0xFF, 0, 0, 0);

            int cnt = 0;
            while ((g_conn_status == CAMERA_UNKNOWN) && (cnt++ < 10))
            {
                richTextBox1.Text += "-1";
                delay(100);
            }

            richTextBox1.Text += "\ncnt = " + cnt.ToString() + "\n";

            if (g_conn_status == DONGLE_NONE)
            {
                richTextBox1.Text += "無連接器\n";
                lb_write_camera_serial.Text = "無連接器";
                lb_write_camera_serial2.Text = "無連接器";
                lb_write_camera_serial2.BackColor = Color.Red;
                lb_write_camera_model.Text = "無連接器";
                tb_info_aa1.Text = "無連接器";
                tb_info_aa1.BackColor = Color.Red;
                playSound(S_FALSE);
            }
            else if (g_conn_status == CAMERA_NONE)
            {
                richTextBox1.Text += "有連接器, 無相機\n";
                lb_write_camera_serial.Text = "有連接器, 無相機";
                lb_write_camera_serial2.Text = "有連接器, 無相機";
                lb_write_camera_serial2.BackColor = Color.Red;
                lb_write_camera_model.Text = "有連接器, 無相機";
                tb_info_aa1.Text = "有連接器, 無相機";
                tb_info_aa1.BackColor = Color.Red;
                playSound(S_FALSE);
            }
            else if (g_conn_status == CAMERA_SENSOR_FAIL)
            {
                richTextBox1.Text += "有連接器, 有相機, 但是相機無法讀寫 " + (check_camera_sensor_fail_cnt + 1).ToString() + "\n";
                lb_write_camera_serial.Text = "相機無法讀寫 " + (check_camera_sensor_fail_cnt + 1).ToString() + "\n";
                lb_write_camera_serial2.Text = "相機無法讀寫 " + (check_camera_sensor_fail_cnt + 1).ToString() + "\n";
                lb_write_camera_serial2.BackColor = Color.Red;
                lb_write_camera_model.Text = "相機無法讀寫 " + (check_camera_sensor_fail_cnt + 1).ToString() + "\n";
                tb_info_aa1.Text = "相機無法讀寫 " + (check_camera_sensor_fail_cnt + 1).ToString() + "\n";
                tb_info_aa1.BackColor = Color.Red;
                playSound(S_FALSE);
                tb_awb_mesg.Text = "相機無法讀寫 " + (check_camera_sensor_fail_cnt + 1).ToString() + "\n";

                richTextBox1.Text += "總共檢查3次, 現在是第 " + check_camera_sensor_fail_cnt.ToString() + " 次";
                check_camera_sensor_fail_cnt++;
                if (check_camera_sensor_fail_cnt == 3)
                {
                    richTextBox1.Text += "已滿3次\n";
                    check_camera_sensor_fail_cnt = 0;
                }
                else
                {
                    get_camera_status();    //再呼叫自己一次
                }
            }
            else if (g_conn_status == CAMERA_OK)
            {
                richTextBox1.Text += "有連接器, 有相機\n";
                lb_write_camera_serial.Text = "有連接器, 有相機";
                lb_write_camera_serial2.Text = "有連接器, 有相機";
                lb_write_camera_serial2.BackColor = Color.White;
                lb_write_camera_model.Text = "有連接器, 有相機";
                tb_info_8.Text = "有連接器, 有相機c";
                tb_info_8.BackColor = Color.White;
            }
            else
            {
                richTextBox1.Text += "狀態不明b, status = " + g_conn_status.ToString() + ", 重測一次 " + (check_camera_status_fail_cnt + 1).ToString() + "\n";
                lb_write_camera_serial.Text = "狀態不明 " + g_conn_status.ToString() + ", 重測一次 " + (check_camera_status_fail_cnt + 1).ToString() + "\n";
                lb_write_camera_serial2.Text = "狀態不明 " + g_conn_status.ToString() + ", 重測一次 " + (check_camera_status_fail_cnt + 1).ToString() + "\n";
                lb_write_camera_serial2.BackColor = Color.Pink;
                lb_write_camera_model.Text = "狀態不明 " + g_conn_status.ToString() + ", 重測一次 " + (check_camera_status_fail_cnt + 1).ToString() + "\n";

                richTextBox1.Text += "總共檢查5次, 現在是第 " + check_camera_status_fail_cnt.ToString() + " 次";
                check_camera_status_fail_cnt++;
                if (check_camera_status_fail_cnt == 5)
                {
                    richTextBox1.Text += "已滿5次\n";
                    check_camera_status_fail_cnt = 0;

                    richTextBox1.Text += "狀態不明b, status = " + g_conn_status.ToString() + "\n";
                    lb_write_camera_serial.Text = "狀態不明 " + g_conn_status.ToString() + "\n";
                    lb_write_camera_serial2.Text = "狀態不明 " + g_conn_status.ToString() + "\n";
                    lb_write_camera_serial2.BackColor = Color.Pink;
                    lb_write_camera_model.Text = "狀態不明 " + g_conn_status.ToString() + "\n";
                }
                else
                {
                    get_camera_status();    //再呼叫自己一次
                }
            }
            bt_camera_info_read.BackColor = SystemColors.ControlLight;
            button8.BackColor = SystemColors.ControlLight;

            if (check_camera_sensor_fail_cnt > 0)
                check_camera_sensor_fail_cnt = 0;
            if (check_camera_status_fail_cnt > 0)
                check_camera_status_fail_cnt = 0;

            return g_conn_status;
        }

        int get_camera_frame_count()
        {
            camera_frame_count = -1;

            serialPort2.DiscardInBuffer();  //丟棄UART buffer內的資料

            int addr_h = 0x4A;
            int addr_l = 0x00;
            DongleAddr_h = (byte)addr_h;
            DongleAddr_l = (byte)addr_l;
            Send_IMS_Data(0xA1, DongleAddr_h, DongleAddr_l, 0);

            int cnt = 0;
            while ((camera_frame_count == -1) && (cnt++ < 10))
            {
                //richTextBox1.Text += "x ";
                delay(100);
            }
            return camera_frame_count;
        }

        private void button97_Click(object sender, EventArgs e)
        {
            richTextBox1.Text += "寫色彩校正預設資料進相機\n";

            g_conn_status = get_camera_status();
            if (g_conn_status != CAMERA_OK)
            {
                richTextBox1.Text += "無相機，不儲存\n";
                return;
            }

            int data_R = 1726;
            int data_B = 1629;
            //new method, write to AWB_PAGE1
            int page = AWB_PAGE1;
            int i;
            for (i = 0; i < 16; i++)
            {
                user_flash_data[i] = 0;
            }

            //ex: DA-52-1A-04-52-1B-D2-52-1E-07-52-1F-08-00-00-00

            user_flash_data[0] = 0xDA;  //header

            user_flash_data[1] = 0x52;  //AWB R H AH
            user_flash_data[2] = 0x1A;  //AWB R H AL
            user_flash_data[3] = (Byte)(data_R / 256);

            user_flash_data[4] = 0x52;  //AWB R L AH
            user_flash_data[5] = 0x1B;  //AWB R L AL
            user_flash_data[6] = (Byte)(data_R % 256);

            user_flash_data[7] = 0x52;  //AWB B H AH
            user_flash_data[8] = 0x1E;  //AWB B H AL
            user_flash_data[9] = (Byte)(data_B / 256);

            user_flash_data[10] = 0x52; //AWB B L AH
            user_flash_data[11] = 0x1F; //AWB B L AL
            user_flash_data[12] = (Byte)(data_B % 256);

            user_flash_data[13] = 0x00; //dummy, no data
            user_flash_data[14] = 0x00; //dummy, no data
            user_flash_data[15] = 0x00; //dummy, no data

            Send_IMS_Data(0xD0, (byte)page, 0, 0);  //write user data to camera flash
            serialPort2.Write(user_flash_data, 0, 16);

            //numericUpDown_brightness.Value = 140;

            do_save_camera_data();

            richTextBox1.Text += "寫色彩校正預設資料進相機\tOK\n";
        }

