        private void bt_debug8_Click(object sender, EventArgs e)
        {
            show_main_message0("debug8 : 量測亮度", S_OK, 30);
            //remove_all_controls_in_pictureBox3();
            //check_all_controls_in_pictureBox3();

            richTextBox1.Text += "量測亮度\n";

            int x_st = 0;
            int y_st = 0;
            int dx = 42;
            int dy = 32;
            int ww = 42;
            int hh = 32;
            double result = -1;
            for (y_st = 0; y_st < 480; y_st += dy)
            {
                for (x_st = 0; x_st < 630; x_st += dx)
                {
                    do
                    {
                        result = measure_brightness(x_st, y_st, ww, hh);
                        richTextBox1.Text += "gray[" + (x_st / dx).ToString() + ", " + (y_st / dy).ToString() + "]=" + ((int)result).ToString() + ";\n";
                    }
                    while (result == -1);
                }
            }
        }

        private void bt_debug9_Click(object sender, EventArgs e)
        {
            if (get_comport_status() == false)
                return;

            g_conn_status = get_camera_status();
            richTextBox1.Text += "g_conn_status = " + g_conn_status.ToString() + "\n";

            if (g_conn_status != CAMERA_OK)
            {
                richTextBox1.Text += "無相機, abort\n";
                return;
            }

            show_main_message0("debug9 : DNS 測試", S_OK, 30);

            flag_get_lenc_status_ready = false;
            Send_IMS_Data(0xA1, 0x50, 0x00, 0); //read 0x5000 ISP CTRL00 for LENC enable

            int cnt = 0;
            while ((flag_get_lenc_status_ready == false) && (cnt++ < 20))
            {
                richTextBox1.Text += "+";
                delay(10);
            }

            if (flag_lenc_enable == false)
            {
                richTextBox1.Text += "LENC OFF\n";
            }
            else
            {
                richTextBox1.Text += "LENC ON\n";
            }

            byte wpt = 0;
            byte bpt = 0;

            for (wpt = 70; wpt <= 160; wpt += 10)
            {
                bpt = (byte)(wpt - 15);

                numericUpDown_wpt.Value = wpt;
                numericUpDown_bpt.Value = bpt;

                DongleData = wpt;
                DongleAddr_h = 0x3A;
                DongleAddr_l = 0x03;
                Send_IMS_Data(0xA0, DongleAddr_h, DongleAddr_l, DongleData);
                delay(10);
                DongleData = bpt;
                DongleAddr_h = 0x3A;
                DongleAddr_l = 0x04;
                Send_IMS_Data(0xA0, DongleAddr_h, DongleAddr_l, DongleData);
                delay(10);

                read_camera_sensor(SENSOR_WPT);

                richTextBox1.Text += "WPT =" + numericUpDown_wpt.Value.ToString() + "\n";

                string foldername;
                foldername = Application.StartupPath + "\\picture_" + numericUpDown_wpt.Value.ToString();
                if (Directory.Exists(foldername) == false)     //確認資料夾是否存在
                {
                    Directory.CreateDirectory(foldername);
                    richTextBox1.Text += "已建立一個新資料夾: " + foldername + "\n";
                }
                else
                {
                    //richTextBox1.Text += "資料夾: " + foldername + " 已存在，不用再建立\n";
                }

                int sharp;
                int dns;
                for (sharp = 0; sharp < 5; sharp++)
                {
                    numericUpDown_sharpness.Value = sharp;

                    for (dns = 0; dns < 5; dns++)
                    {
                        show_main_message0("測試  " + numericUpDown_wpt.Value.ToString() + "   " + dns.ToString() + "   " + sharp.ToString(), S_OK, 30);
                        numericUpDown_denoise.Value = dns;
                        delay(500);
                        //save_image_to_local_drive();
                        //save_image_to_local_drive(foldername);
                    }
                }
            }

            richTextBox1.Text += "debug9 test SP\n";

            show_main_message0("debug9 : 測試完成", S_OK, 500);
        }

        private void bt_debug10_Click(object sender, EventArgs e)
        {
            richTextBox1.Clear();

            richTextBox1.Text += "自動曝光關閉\n";

            byte SendData = 0;

            DongleAddr_h = 0x35;
            DongleAddr_l = 0x03;
            SendData = 0x03;
            richTextBox1.Text += "位址 0x" + DongleAddr_h.ToString("X2") + DongleAddr_l.ToString("X2") + "\t數值 : 0x " + SendData.ToString("X2") + " = " + SendData.ToString() + "\n";
            Send_IMS_Data(0xA0, DongleAddr_h, DongleAddr_l, SendData);

            int cx = 0;
            int cy = 0;
            int W = 640;
            int H = 480;
            int ww = 180;
            int hh = 180;
            double result = -1;

            int i = 0;

            for (i = 0; i < 490; i += 1)
            {
                //richTextBox1.Text += "曝光設定 : " + i.ToString() + "\n";

                DongleAddr_h = 0x35;
                DongleAddr_l = 0x01;

                SendData = (byte)(i / 256);
                Send_IMS_Data(0xA0, DongleAddr_h, DongleAddr_l, SendData);
                delay(100);
                DongleAddr_h = 0x35;
                DongleAddr_l = 0x02;
                SendData = (byte)(i % 256);
                Send_IMS_Data(0xA0, DongleAddr_h, DongleAddr_l, SendData);
                delay(500);


                cx = (W - ww) / 2;
                cy = (H - hh) / 2;
                result = measure_brightness(cx, cy, ww, hh);
                //richTextBox1.Text += "測光位置(" + cx.ToString() + ", " + cy.ToString() + ", " + ww.ToString() + ", " + hh.ToString() + ")\t結果 : " + result.ToString() + "\n";
                //richTextBox1.Text += "i = " + i.ToString() + ", brightness = " + result.ToString() + "\n";
                richTextBox1.Text += "gray[" + i.ToString() + "]=" + result.ToString() + ";\n";

                delay(100);

            }
        }

        private void bt_debug11_Click(object sender, EventArgs e)
        {
            richTextBox1.Text += "測試燒錄序號";
            string serial_data = "ABC0123456789  @";
            richTextBox1.Text += "相機序號 : " + serial_data + "\n";
            richTextBox1.Text += "相機序號長度 : " + serial_data.Length.ToString() + "\n";

            int i;

            byte[] sn_data_tmp = new byte[16];
            for (i = 0; i < serial_data.Length; i++)
            {
                sn_data_tmp[i] = (byte)serial_data[i];
                //richTextBox_plc.Text += "\ni = " + i.ToString() + " tmp data : " + serial_data[i].ToString();
            }
            //richTextBox_plc.Text += "\n";

            //這裡是寫入資料
            Send_IMS_Data(0xC0, 0x12, 0x34, 0x56);   //camera serial write

            serialPort2.Write(sn_data_tmp, 0, 16);

            richTextBox1.Text += "ok\n";

            return;

            richTextBox1.Text += "\n\nread camera serial b\n";
            //get camera serial
            Get_IMS_Data(0, 0xAA, 0xAA);
            int cnt = 0;
            while ((flag_wait_receive_data == 1) && (cnt++ < 20))
            {
                richTextBox1.Text += "+";
                delay(100);
            }
            flag_wait_receive_data = 0;


            return;

        }

