            delay(20);
            */

            //RGB改為1倍
            trackBar_R.Value = 0x400;
            trackBar_G.Value = 0x400;
            trackBar_B.Value = 0x400;

            numericUpDown_R.Value = trackBar_R.Value;
            numericUpDown_G.Value = trackBar_G.Value;
            numericUpDown_B.Value = trackBar_B.Value;

            byte dd;
            int SendData = trackBar_R.Value;
            dd = (byte)(SendData / 256);
            DongleAddr_h = 0x52;
            DongleAddr_l = 0x1A;
            Send_IMS_Data(0xA0, DongleAddr_h, DongleAddr_l, dd);
            DongleAddr_h = 0x52;
            DongleAddr_l = 0x1B;
            dd = (byte)(SendData % 256);
            Send_IMS_Data(0xA0, DongleAddr_h, DongleAddr_l, dd);

            SendData = trackBar_G.Value;
            dd = (byte)(SendData / 256);
            DongleAddr_h = 0x52;
            DongleAddr_l = 0x1C;
            Send_IMS_Data(0xA0, DongleAddr_h, DongleAddr_l, dd);
            DongleAddr_h = 0x52;
            DongleAddr_l = 0x1D;
            dd = (byte)(SendData % 256);
            Send_IMS_Data(0xA0, DongleAddr_h, DongleAddr_l, dd);

            SendData = trackBar_B.Value;
            dd = (byte)(SendData / 256);
            DongleAddr_h = 0x52;
            DongleAddr_l = 0x1E;
            Send_IMS_Data(0xA0, DongleAddr_h, DongleAddr_l, dd);
            DongleAddr_h = 0x52;
            DongleAddr_l = 0x1F;
            dd = (byte)(SendData % 256);
            Send_IMS_Data(0xA0, DongleAddr_h, DongleAddr_l, dd);
        }

