        private void btn_cmx01_click(object sender, EventArgs e)
        {
            double cmx00d = double.Parse(tb_cmx_00.Text);
            double cmx01d = double.Parse(tb_cmx_01.Text);
            double cmx02d = double.Parse(tb_cmx_02.Text);
            double cmx10d = double.Parse(tb_cmx_10.Text);
            double cmx11d = double.Parse(tb_cmx_11.Text);
            double cmx12d = double.Parse(tb_cmx_12.Text);
            double cmx20d = double.Parse(tb_cmx_20.Text);
            double cmx21d = double.Parse(tb_cmx_21.Text);
            double cmx22d = double.Parse(tb_cmx_22.Text);

            richTextBox1.Text += "Color Matrix\n";
            richTextBox1.Text += cmx00d.ToString() + "\t" + cmx01d.ToString() + "\t" + cmx02d.ToString() + "\n";
            richTextBox1.Text += cmx10d.ToString() + "\t" + cmx11d.ToString() + "\t" + cmx12d.ToString() + "\n";
            richTextBox1.Text += cmx20d.ToString() + "\t" + cmx21d.ToString() + "\t" + cmx22d.ToString() + "\n";

            cmx00 = cmx00d;
            cmx01 = cmx01d;
            cmx02 = cmx02d;
            cmx10 = cmx10d;
            cmx11 = cmx11d;
            cmx12 = cmx12d;
            cmx20 = cmx20d;
            cmx21 = cmx21d;
            cmx22 = cmx22d;

            string filename = @"D:\_git\vcs\_1.data\______test_files1\ims01.bmp";
            Bitmap bitmap1 = new Bitmap(filename);

            int xx;
            int yy;
            Color p;

            for (yy = 0; yy < bitmap1.Height; yy++)
            {
                for (xx = 0; xx < bitmap1.Width; xx++)
                {
                    p = bitmap1.GetPixel(xx, yy);

                    //RGB 轉 YUV, 使用 Color Matrix
                    RGB pp = new RGB(p.R, p.G, p.B);
                    YUV yyy = new YUV();
                    RGB rrr = new RGB();
                    yyy = RGBToYUV_new(pp);

                    //RGBToYUV_new

                    //YUV 轉 RGB, 固定
                    rrr = YUVToRGB(yyy);
                    bitmap1.SetPixel(xx, yy, Color.FromArgb(rrr.R, rrr.G, rrr.B));
                }
            }
            pictureBox1.Image = bitmap1;
        }

        int[] total_R_old = new int[15];
        int[] total_G_old = new int[15];
        int[] total_B_old = new int[15];
        private void btn_cmx02_click(object sender, EventArgs e)
        {
            int pbox1_w = pictureBox1.Image.Width;
            int pbox1_h = pictureBox1.Image.Height;
            Bitmap bmp = new Bitmap(pictureBox1.Image);
            Graphics g = Graphics.FromImage(bmp);

            SolidBrush drawBrush = new SolidBrush(Color.Gold);
            Font drawFont1 = new Font("Arial", 4, GraphicsUnit.Millimeter);
            //g.DrawString(pbox1_w.ToString() + "X" + pbox1_h.ToString(), drawFont1, drawBrush, 20, 20);

            int i = 0;
            int j = 0;
            int k = 0;
            int w = 50;
            int h = 50;
            int ii = 0;
            int jj = 0;
            for (j = 100; j < 400; j += 100)
            {
                for (i = 100; i < 600; i += 100)
                {
                    //g.DrawRectangle(new Pen(Color.Green, 1), i, j, w, h);
                    g.DrawRectangle(new Pen(Color.Green, 1), i - 2, j - 2, w + 4, h + 4);
                    //g.DrawString(k.ToString(), drawFont1, drawBrush, i, j);

                    int total_R = 0;
                    int total_G = 0;
                    int total_B = 0;
                    Color pt;

                    for (jj = 0; jj < h; jj++)
                    {
                        for (ii = 0; ii < w; ii++)
                        {
                            pt = bmp.GetPixel(i + ii, j + jj);
                            total_R += pt.R;
                            total_G += pt.G;
                            total_B += pt.B;
                        }
                    }

                    string text = (total_R / (w * h)).ToString() + " / " + (total_G / (w * h)).ToString() + " / " + (total_B / (w * h)).ToString();
                    g.DrawString(text, drawFont1, drawBrush, i - 25, j + h + 10);

                    text = ((total_R_old[k] - total_R) / (w * h)).ToString() + " / " + ((total_G_old[k] - total_G) / (w * h)).ToString() + " / " + ((total_B_old[k] - total_B) / (w * h)).ToString();
                    g.DrawString(text, drawFont1, drawBrush, i - 25, j + h + 10 + 18);

                    total_R_old[k] = total_R;
                    total_G_old[k] = total_G;
                    total_B_old[k] = total_B;
                    k++;
                }
            }

            drawBrush = new SolidBrush(Color.Red);
            drawFont1 = new Font("Arial", 10, GraphicsUnit.Millimeter);
            g.DrawString(k.ToString(), drawFont1, drawBrush, 20, 20);
            pictureBox1.Image = bmp;
        }

