        private void btn_read_cmx_click(object sender, EventArgs e)
        {
            if (get_comport_status() == false)
                return;

            show_main_message_cmx_lenc("讀取", S_OK, 20);

            tb0.Text = "";
            tb1.Text = "";
            tb2.Text = "";
            tb3.Text = "";
            tb4.Text = "";
            tb5.Text = "";
            tb6.Text = "";
            tb7.Text = "";
            tb8.Text = "";
            tb0h.Text = "";
            tb1h.Text = "";
            tb2h.Text = "";
            tb3h.Text = "";
            tb4h.Text = "";
            tb5h.Text = "";
            tb6h.Text = "";
            tb7h.Text = "";
            tb8h.Text = "";
            tb_cmx_u_r.Text = "";
            tb_cmx_u_g.Text = "";
            tb_cmx_u_b.Text = "";
            tb_cmx_v_r.Text = "";
            tb_cmx_v_g.Text = "";
            tb_cmx_v_b.Text = "";

            DongleAddr_h = 0x56;
            DongleAddr_l = 0x00;    //CMX11
            Send_IMS_Data(0xA1, DongleAddr_h, DongleAddr_l, 0);

            delay(100);

            DongleAddr_h = 0x56;
            DongleAddr_l = 0x01;    //CMX12
            Send_IMS_Data(0xA1, DongleAddr_h, DongleAddr_l, 0);

            delay(100);

            DongleAddr_h = 0x56;
            DongleAddr_l = 0x02;    //CMX13
            Send_IMS_Data(0xA1, DongleAddr_h, DongleAddr_l, 0);

            delay(100);

            DongleAddr_h = 0x56;
            DongleAddr_l = 0x03;    //CMX14
            Send_IMS_Data(0xA1, DongleAddr_h, DongleAddr_l, 0);

            delay(100);

            DongleAddr_h = 0x56;
            DongleAddr_l = 0x04;    //CMX15
            Send_IMS_Data(0xA1, DongleAddr_h, DongleAddr_l, 0);

            delay(100);

            DongleAddr_h = 0x56;
            DongleAddr_l = 0x05;    //CMX16
            Send_IMS_Data(0xA1, DongleAddr_h, DongleAddr_l, 0);

            delay(100);

            DongleAddr_h = 0x56;
            DongleAddr_l = 0x12;    //CMX SIGN
            Send_IMS_Data(0xA1, DongleAddr_h, DongleAddr_l, 0);

            delay(100);
            DongleAddr_h = 0x56;
            DongleAddr_l = 0x15;    //CMX CTRL
            Send_IMS_Data(0xA1, DongleAddr_h, DongleAddr_l, 0);

            delay(100);

            DongleAddr_h = 0x50;
            DongleAddr_l = 0x01;    //ISP CTRL01
            Send_IMS_Data(0xA1, DongleAddr_h, DongleAddr_l, 0);
        }

