        private void btn_direction_U_click(object sender, EventArgs e)
        {
            int direction = 0;
            if (cb_direction_R.Checked == true)
            {
                show_main_message_cmx_lenc("上 R", S_OK, 10);
                direction = tbar1r.Value;
                if (direction > 0)
                {
                    direction -= 1;
                    tbar1r.Value = direction;
                    tbar_mouse_up_lenc(tbar1r, e);
                }
            }
            if (cb_direction_G.Checked == true)
            {
                show_main_message_cmx_lenc("上 G", S_OK, 10);
                direction = tbar1g.Value;
                if (direction > 0)
                {
                    direction -= 1;
                    tbar1g.Value = direction;
                    tbar_mouse_up_lenc(tbar1g, e);
                }
            }
            if (cb_direction_B.Checked == true)
            {
                show_main_message_cmx_lenc("上 B", S_OK, 10);
                direction = tbar1b.Value;
                if (direction > 0)
                {
                    direction -= 1;
                    tbar1b.Value = direction;
                    tbar_mouse_up_lenc(tbar1b, e);
                }
            }
        }

