        private void tb0r_KeyPress(object sender, KeyPressEventArgs e)
        {
            e.Handled = check_textbox_number(e);

            if (e.KeyChar == (Char)13)  //收到Enter後, 執行動作
            {
                int value = int.Parse(tb0r.Text);
                if ((value <= 0) || value > 1023)
                {
                    show_main_message_cmx_lenc("R0錯誤", S_OK, 10);
                }
                else
                {
                    tbar0r.Value = value;
                    tbar_mouse_up_lenc(tbar0r, e);
                }
            }
        }

