        void do_ov_test()
        {
            int pbx5_w = 610;       //最後顯示出來的圖的大小
            int pbx5_h = 1000;
            richTextBox1.Text += "pbx5_w = " + pbx5_w.ToString() + ", pbx5_h = " + pbx5_h.ToString() + "\n";
            pictureBox5.Visible = true;
            pictureBox5.BackColor = Color.Pink;
            pictureBox5.Size = new Size(pbx5_w, pbx5_h);
            pictureBox5.BringToFront();
            pictureBox5.Location = new Point(0, 0);

            Bitmap bmp5 = new Bitmap(pbx5_w, pbx5_h);
            g5 = Graphics.FromImage(bmp5);
            g5.FillRectangle(new SolidBrush(Color.White), 0, 0, bmp5.Width, bmp5.Height);   //整個背景
            g5.DrawString("OV Test", new Font("標楷體", 22), new SolidBrush(Color.Red), new PointF(40, 10));

            pictureBox5.Image = bmp5;

            GC.Collect();       //回收資源

            delay(10);

            flag_get_lenc_status_ready = false;
            Send_IMS_Data(0xA1, 0x50, 0x00, 0); //read 0x5000 ISP CTRL00 for LENC enable

            int cnt = 0;
            while ((flag_get_lenc_status_ready == false) && (cnt++ < 20))
            {
                richTextBox1.Text += "+";
                delay(10);
            }

            add_ov_test_controls();

            return;
        }

        void add_ov_test_controls()
        {
            richTextBox1.Visible = false;

            int x_st = 30;
            int y_st = 80;
            int dx = 150;
            int dy = 37;
            //int offset = 0;
            int w = 0;  //控件寬度
            int h = 0;  //控件高度

            //int region_y = 235;

            // 實例化控件

            lb_main_mesg_ov_test.Text = "";
            lb_main_mesg_ov_test.Font = new Font("標楷體", 22);
            lb_main_mesg_ov_test.ForeColor = Color.Red;
