        void do_dns_sharpness_test()
        {
            int sharpness = 0;
            int dns = 0;

            int recursive_dns = 1;

            DongleAddr_h = 0x55;
            DongleAddr_l = 0x0D;
            DongleData = (byte)recursive_dns;
            Send_IMS_Data(0xA0, DongleAddr_h, DongleAddr_l, DongleData);

            for (sharpness = 0; sharpness < 10; sharpness += 1)
            {
                for (dns = 0; dns < 10; dns += 1)
                {
                    comboBox_sharpness.SelectedIndex = sharpness;
                    comboBox_denoise.SelectedIndex = dns;

                    richTextBox1.Text += "Sharp = " + sharpness.ToString() + ", DNS = " + dns.ToString() + "\n";

                    if (recursive_dns == 0)
                        tb_mesg.Text = "關 RDNS, Sharp = " + sharpness.ToString() + ", DNS = " + dns.ToString();
                    else
                        tb_mesg.Text = "開 RDNS, Sharp = " + sharpness.ToString() + ", DNS = " + dns.ToString();

                    delay(700);

                    save_image_to_local_drive();        //順道本地存圖

                    delay(100);
                }
            }
        }

        int trackBar_register_addr = 0;
        private void tbar_mouse_down_register(object sender, EventArgs e)
        {
        }

        private void tbar_mouse_up_register(object sender, EventArgs e)
        {
            //richTextBox_ov_test.Text += "addr = 0x" + trackBar_register_addr.ToString("X4") + " ";
            if ((trackBar_register_addr < 0x5800) || (trackBar_register_addr > 0x5900))
            {
                richTextBox_ov_test.Text += "X ";
                return;
            }

            if (tb_1a.Text.Length <= 0)
                return;
            int addr_h = Convert.ToInt32(tb_1a.Text, 16);
            DongleAddr_h = (byte)addr_h;
            //DongleAddr_l = (byte)addr_l;
            DongleData = (byte)int.Parse(tb_4a.Text);
            //Send_IMS_Data(0xA0, DongleAddr_h, DongleAddr_l, DongleData);
        }

        private void tbar_scroll_register(object sender, EventArgs e)
        {
            tb_4a.Text = trackBar_register.Value.ToString();
        }

        private void ovTestClick(object sender, EventArgs e)
        {
            richTextBox_ov_test.Text += "你按了按鈕 Name : " + ((Button)sender).Name + "\n";

            byte cnt1 = 0;

            if (((Button)sender).Name == "bt_ov_test00")
            {
                //bt_ov_test00_Click(sender, e);

                cnt1 = 0;
                DongleAddr_h = 0x50;
                DongleAddr_l = 0x80;
                DongleData = (byte)(cnt1 * 4 + 0);
                Send_IMS_Data(0xA0, DongleAddr_h, DongleAddr_l, DongleData);
            }
            else if (((Button)sender).Name == "bt_ov_test01")
            {
                //bt_ov_test01_Click(sender, e);
                cnt1 = 0;
                DongleAddr_h = 0x50;
                DongleAddr_l = 0x80;
                DongleData = (byte)(cnt1 * 4 + 128);
                Send_IMS_Data(0xA0, DongleAddr_h, DongleAddr_l, DongleData);

            }
            else if (((Button)sender).Name == "bt_ov_test02")
            {
                //bt_ov_test02_Click(sender, e);
                cnt1 = 1;
                DongleAddr_h = 0x50;
                DongleAddr_l = 0x80;
                DongleData = (byte)(cnt1 * 4 + 128);
                Send_IMS_Data(0xA0, DongleAddr_h, DongleAddr_l, DongleData);

            }
            else if (((Button)sender).Name == "bt_ov_test03")
            {
                //bt_ov_test03_Click(sender, e);
                cnt1 = 2;
                DongleAddr_h = 0x50;
                DongleAddr_l = 0x80;
                DongleData = (byte)(cnt1 * 4 + 128);
                Send_IMS_Data(0xA0, DongleAddr_h, DongleAddr_l, DongleData);
            }
            else if (((Button)sender).Name == "bt_ov_test04")
            {
                richTextBox_ov_test.Text += "特效 正常\n";

                //Normal (off)
                //78 5001 3f
                //78 5800 2

                DongleData = 0x3f;
                DongleAddr_h = 0x50;
                DongleAddr_l = 0x01;
                Send_IMS_Data(0xA0, DongleAddr_h, DongleAddr_l, DongleData);

                DongleData = 0x02;
                DongleAddr_h = 0x58;
                DongleAddr_l = 0x00;
                Send_IMS_Data(0xA0, DongleAddr_h, DongleAddr_l, DongleData);
            }
            else if (((Button)sender).Name == "bt_ov_test05")
            {
                richTextBox_ov_test.Text += "特效 黑白\n";

                //Black and white
                //78 5001 3f
                //78 5800 22

                DongleData = 0x3f;
                DongleAddr_h = 0x50;
                DongleAddr_l = 0x01;
                Send_IMS_Data(0xA0, DongleAddr_h, DongleAddr_l, DongleData);

                DongleData = 0x22;
                DongleAddr_h = 0x58;
                DongleAddr_l = 0x00;
                Send_IMS_Data(0xA0, DongleAddr_h, DongleAddr_l, DongleData);
            }
