        private int W = 0;  //原圖的寬
        private int H = 0;  //原圖的高
        private int w = 0;  //擷取圖的寬
        private int h = 0;  //擷取圖的高
        int x_st = 0;
        int y_st = 0;
        int x_sp = 0;
        int y_sp = 0;
        int[] sensor_brightness_data = new int[256];
        int max = 255;
        int min = 0;
        int brightness = 128;
        int brightness_old = 128;
        int contrast = 128;
        int contrast_old = 128;

        void measure_brightness(PictureBox pbox1, PictureBox pbox2)
        {
            if (pbox1.Image == null)
            {
                richTextBox_ov_test.Text += pbox1.Name + " 無影像, 離開\n";
                return;
            }

            sensor_brightness_data = new int[256];

            if (checkBox1.Checked == true)
            {
                x_st = 0;
                y_st = 0;
                w = 640;
                h = 480;
            }
            else
            {
                x_st = 50;
                y_st = 50;
                w = 640 - 100;
                h = 480 - 100;
            }

            x_st = 50;
            y_st = 50;
            w = 640 - 100;
            h = 480 - 100;

            Bitmap bitmap1 = (Bitmap)pbox1.Image;
            int W = bitmap1.Width;
            int H = bitmap1.Height;
            //richTextBox_ov_test.Text += "W = " + W.ToString() + ", H = " + H.ToString() + "\n";
            int i;
            int j;
            int total_points = 0;

            for (j = y_st; j < (y_st + h); j++)
            {
                for (i = x_st; i < (x_st + w); i++)
                {
                    //double y = rgb.R * .299000 + rgb.G * .587000 + rgb.B * .114000;

                    byte rrr = (byte)((double)bitmap1.GetPixel(i, j).R * .299000 + (double)bitmap1.GetPixel(i, j).G * .587000 + (double)bitmap1.GetPixel(i, j).B * .114000);
                    //richTextBox_ov_test.Text += rrr.ToString() + "-";
                    sensor_brightness_data[rrr]++;
                    total_points++;
                }
            }

            //一律忽視最亮和最暗的數值
            sensor_brightness_data[0] = 0;
            sensor_brightness_data[255] = 0;

            //richTextBox_ov_test.Text += "共有 " + total_points.ToString() + " 個點\n";

            draw_brightness(pbox2);
        }

        void draw_brightness(PictureBox pbox)
        {
            int i;
            int most = 0;
            for (i = 0; i < 256; i++)
            {
                //richTextBox_ov_test.Text += sensor_brightness_data[i].ToString() + " ";
                if (sensor_brightness_data[i] > most)
                    most = sensor_brightness_data[i];
                if (sensor_brightness_data[i] == 0)
                    sensor_brightness_data[i] = 5;
            }
            //richTextBox_ov_test.Text += "\n最多 " + most.ToString() + "\n";

            int ww = 512;
            int hh1 = 300;
            int hh2 = 256;
            Bitmap bitmap2 = new Bitmap(ww, hh1);
            Graphics g2 = Graphics.FromImage(bitmap2);
            g2.Clear(Color.Pink);
            Pen p = new Pen(Color.Red, 2);

            double ratio = 0;
            ratio = (double)hh2 / most;

            //richTextBox_ov_test.Text += "ratio = " + ratio.ToString() + "\n";

            for (i = 0; i < 256; i++)
            {
                //g2.FillRectangle(Brushes.Red, i * 2, 0, 2, (float)(sensor_brightness_data[i] * ratio));
                g2.FillRectangle(Brushes.Red, i * 2, hh2 - (float)(sensor_brightness_data[i] * ratio), 2, (float)(sensor_brightness_data[i] * ratio));
            }

            g2.DrawRectangle(p, 0 + 1, 0 + 1, ww - 2, hh1 - 2);
            g2.DrawRectangle(p, 0 + 1, 0 + 1, ww - 2, hh2 - 2);


            Brush b = new SolidBrush(Color.FromArgb(33, Color.RoyalBlue.R, Color.RoyalBlue.G, Color.RoyalBlue.B));

            g2.FillRectangle(b, min * 2, 0, (max - min) * 2, hh1);


            p = new Pen(Color.Green, 3);

            g2.DrawLine(p, min * 2, hh2, max * 2, 0);

            Font f = new Font("標楷體", 20);

            if ((min >= 0) && (min <= 103))
            {
                g2.DrawString(min.ToString(), f, new SolidBrush(Color.Blue), new PointF(min * 2, hh2));
            }
            else if (min < 0)
            {
                g2.DrawString(min.ToString(), f, new SolidBrush(Color.Blue), new PointF(0, hh2));
            }
            else
            {
                g2.DrawString(min.ToString(), f, new SolidBrush(Color.Blue), new PointF(103 * 2, hh2));
            }

            if ((max <= 255) && (max >= 152))
            {
                g2.DrawString(max.ToString(), f, new SolidBrush(Color.Blue), new PointF(max * 2 - 50, hh2));
            }
            else if (max > 255)
            {
                g2.DrawString(max.ToString(), f, new SolidBrush(Color.Blue), new PointF(512 - 50, hh2));
            }
            else
            {
                g2.DrawString(max.ToString(), f, new SolidBrush(Color.Blue), new PointF(152 * 2 - 50, hh2));
            }
            pbox.Image = bitmap2;
        }



        bool flag_pictureBox4_mouse_down = false;
        private void pictureBox4_MouseDown(object sender, MouseEventArgs e)
        {
            flag_pictureBox4_mouse_down = true;
            //richTextBox1.Text += "Down : (" + e.X.ToString() + ", " + e.Y.ToString() + ")\n";
            pictureBox4_position_x_old = e.X;
            pictureBox4_position_y_old = e.Y;
        }

        private void pictureBox4_MouseMove(object sender, MouseEventArgs e)
        {
            if (flag_pictureBox4_mouse_down == true)
            {
                //richTextBox1.Text += "Up : (" + e.X.ToString() + ", " + e.Y.ToString() + ")\n";
                int dx = e.X - pictureBox4_position_x_old;
                int dy = e.Y - pictureBox4_position_y_old;

                //richTextBox1.Text += "dx, dy : (" + dx.ToString() + ", " + dy.ToString() + ")\n";
                pictureBox4.Location = new Point(pictureBox4.Location.X + dx, pictureBox4.Location.Y + dy);
            }
        }

        private void pictureBox4_MouseUp(object sender, MouseEventArgs e)
        {
            flag_pictureBox4_mouse_down = false;
            //richTextBox1.Text += "Up : (" + e.X.ToString() + ", " + e.Y.ToString() + ")\n";
            int dx = e.X - pictureBox4_position_x_old;
            int dy = e.Y - pictureBox4_position_y_old;

            //richTextBox1.Text += "dx, dy : (" + dx.ToString() + ", " + dy.ToString() + ")\n";
            pictureBox4.Location = new Point(pictureBox4.Location.X + dx, pictureBox4.Location.Y + dy);
        }

        void show_hex2bit4(int value)
        {
            //richTextBox1.Text += "show_hex2bit4\n";
            if (((value >> 3) & 0x01) == 0x01)
                cb_lenc3.Checked = true;
            else
                cb_lenc3.Checked = false;
            if (((value >> 2) & 0x01) == 0x01)
                cb_lenc2.Checked = true;
            else
                cb_lenc2.Checked = false;
            if (((value >> 1) & 0x01) == 0x01)
                cb_lenc1.Checked = true;
            else
                cb_lenc1.Checked = false;
            if (((value >> 0) & 0x01) == 0x01)
                cb_lenc0.Checked = true;
            else
                cb_lenc0.Checked = false;
        }

