        bool flag_pictureBox5_mouse_down = false;
        private void pictureBox5_MouseDown(object sender, MouseEventArgs e)
        {
            flag_pictureBox5_mouse_down = true;
            //richTextBox1.Text += "Down : (" + e.X.ToString() + ", " + e.Y.ToString() + ")\n";
            pictureBox5_position_x_old = e.X;
            pictureBox5_position_y_old = e.Y;
        }

        private void pictureBox5_MouseMove(object sender, MouseEventArgs e)
        {
            if (flag_pictureBox5_mouse_down == true)
            {
                //richTextBox1.Text += "Up : (" + e.X.ToString() + ", " + e.Y.ToString() + ")\n";
                int dx = e.X - pictureBox5_position_x_old;
                int dy = e.Y - pictureBox5_position_y_old;

                //richTextBox1.Text += "dx, dy : (" + dx.ToString() + ", " + dy.ToString() + ")\n";
                pictureBox5.Location = new Point(pictureBox5.Location.X + dx, pictureBox5.Location.Y + dy);
            }
        }

        private void pictureBox5_MouseUp(object sender, MouseEventArgs e)
        {
            flag_pictureBox5_mouse_down = false;
            //richTextBox1.Text += "Up : (" + e.X.ToString() + ", " + e.Y.ToString() + ")\n";
            int dx = e.X - pictureBox5_position_x_old;
            int dy = e.Y - pictureBox5_position_y_old;

            //richTextBox1.Text += "dx, dy : (" + dx.ToString() + ", " + dy.ToString() + ")\n";
            pictureBox5.Location = new Point(pictureBox5.Location.X + dx, pictureBox5.Location.Y + dy);
        }

