        private void bt_write_input_select_Click(object sender, EventArgs e)
        {
            int select_user = 0;
            if (rb_input00.Checked == true)
            {
                select_user = 0;
            }
            else if (rb_input01.Checked == true)
            {
                select_user = 1;
            }
            else if (rb_input10.Checked == true)
            {
                select_user = 2;
            }
            else if (rb_input11.Checked == true)
            {
                select_user = 3;
            }
            else
            {
                select_user = 0;
            }

            richTextBox_ov_test.Text += "select_user = " + select_user.ToString() + "\n";

            bt_read_input_select_Click(sender, e);
            int cnt = 0;
            flag_wait_receive_data = 1;
            while ((flag_wait_receive_data == 1) && (cnt++ < 20))
            {
                richTextBox1.Text += "+";
                delay(100);
            }
            flag_wait_receive_data = 0;

            int select_old = 0;
            if (rb_input00.Checked == true)
            {
                select_old = 0;
            }
            else if (rb_input01.Checked == true)
            {
                select_old = 1;
            }
            else if (rb_input10.Checked == true)
            {
                select_old = 2;
            }
            else if (rb_input11.Checked == true)
            {
                select_old = 3;
            }
            else
            {
                select_old = 0;
            }
            richTextBox_ov_test.Text += "select_old = " + select_old.ToString() + "\n";

            if (select_old == select_user)
            {
                lb_ctrl.Text = "0x" + data_ctrl.ToString("X2") + " 無需重設";
                return;
            }

            richTextBox_ov_test.Text += "setup_old = " + data_ctrl.ToString("X2") + "\n";

            data_ctrl = (data_ctrl & 0x3f) + select_user * 64;

            richTextBox_ov_test.Text += "setup_new = " + data_ctrl.ToString("X2") + "\n";

            lb_ctrl.Text = "0x" + data_ctrl.ToString("X2") + " 新值";

            richTextBox_ov_test.Text += "Write 0x5002 as " + data_ctrl.ToString("X2") + "\n";
            Send_IMS_Data2(0x5002, (byte)data_ctrl);

            if (select_user == 0)
            {
                rb_input00.Checked = true;
                rb_input01.Checked = false;
                rb_input10.Checked = false;
                rb_input11.Checked = false;
            }
            else if (select_user == 1)
            {
                rb_input00.Checked = false;
                rb_input01.Checked = true;
                rb_input10.Checked = false;
                rb_input11.Checked = false;
            }
            else if (select_user == 2)
            {
                rb_input00.Checked = false;
                rb_input01.Checked = false;
                rb_input10.Checked = true;
                rb_input11.Checked = false;

            }
            else if (select_user == 3)
            {
                rb_input00.Checked = false;
                rb_input01.Checked = false;
                rb_input10.Checked = false;
                rb_input11.Checked = true;
            }
            else
            {
                rb_input00.Checked = false;
                rb_input01.Checked = false;
                rb_input10.Checked = false;
                rb_input11.Checked = false;
            }
            //bt_read_input_select_Click
        }

        bool check_comport_connection()
        {
            if (flag_david_test3 == true)
            {
                this.Cursor = Cursors.Default;
                flag_comport_ok = true;
                flag_comport_connection_ok = true;
                return true;
            }

            bool flag_comport_connection = false;
            if (flag_comport_ok == false)
            {
                richTextBox1.Text += "未連上 comport 1\n";
                flag_comport_connection = false;
                return flag_comport_connection;
            }

            if (serialPort2.IsOpen == false)
            {
                richTextBox1.Text += "未連上 comport 2\n";
                flag_comport_connection = false;
                return flag_comport_connection;
            }

            flag_comport_connection_ok = false;
            //開啟程式時, 把所有serialPort的資料讀出來, 並丟棄之
            serialPort2.DiscardInBuffer();  //丟棄UART buffer內的資料

            if (flag_enaglb_automation == false)
            {
                //一般使用
                Send_IMS_Data0(0xFF, 0x11, 0x52, 0x00); //directly send uart command
            }
            else
            {
                //自動化製程使用
                if (flag_automation_mode == MODE_AWB)   //自動化製程 + 色調
                    Send_IMS_Data0(0xFF, 0x11, 0x52, 0xAB); //directly send uart command
                else if (flag_automation_mode == MODE_WRITE_DATA)   //自動化製程 + 燒錄
                    Send_IMS_Data0(0xFF, 0x11, 0x52, 0xCD); //directly send uart command
                else
                    Send_IMS_Data0(0xFF, 0x11, 0x52, 0x00); //directly send uart command
            }

            DateTime start_time = DateTime.Now;
            //richTextBox1.Text += "時間1 : " + DateTime.Now.ToString() + "\n";
            int cnt = 0;
            while ((flag_comport_connection_ok == false) && (cnt++ < 12))
            {
                richTextBox1.Text += "x";
                delay(10);

                //再發一次命令  TBD
                /* TBD
                if ((cnt % 15) == 14)
                {
                    richTextBox1.Text += "無回應, 再發一次命令1\n";
                    Send_IMS_Data0(0xFF, 0x11, 0x52, 0x00); //directly send uart command
                    serialPort2.DiscardInBuffer();  //丟棄UART buffer內的資料
                    cnt = 0;
                }
                */
            }
            richTextBox1.Text += "\ncnt = " + cnt.ToString() + "\n";    //usually cnt = 4
            if (cnt > 30)
                richTextBox1.Text += "XXXXXXXXXXXXX\n";

            if ((cnt > connect_comport_cnt_max) && (cnt < 41))
            {
                connect_comport_cnt_max = cnt;
                richTextBox1.Text += "let cnt = " + cnt.ToString() + "\n";
                //tb_awb_mesg.Text = connect_comport_cnt_max.ToString();
                //Application.DoEvents();
            }

            //tb_awb_mesg.Text = connect_comport_cnt_max.ToString();
            Application.DoEvents();

            double diff_time = (DateTime.Now - start_time).TotalSeconds;
            richTextBox1.Text += "時間 : " + diff_time.ToString() + "\n";

            richTextBox1.Text += "結果 " + flag_comport_connection_ok.ToString() + "\n";

            return flag_comport_connection_ok;
        }

        void check_automation_default_folder()
        {
            string Path;
            //檢查存csv的資料夾
            Path = Application.StartupPath + "\\automation_csv";
            if (Directory.Exists(Path) == false)     //確認資料夾是否存在
            {
                Directory.CreateDirectory(Path);
                richTextBox1.Text += "已建立一個新資料夾: " + Path + "\n";
            }
            else
            {
                richTextBox1.Text += "資料夾: " + Path + " 已存在，不用再建立\n";
            }

            //檢查存圖片的資料夾
            Path = Application.StartupPath + "\\automation_picture";
            if (Directory.Exists(Path) == false)     //確認資料夾是否存在
            {
                Directory.CreateDirectory(Path);
                richTextBox1.Text += "已建立一個新資料夾: " + Path + "\n";
            }
            else
            {
                richTextBox1.Text += "資料夾: " + Path + " 已存在，不用再建立\n";
            }
        }

        void check_automation_default_setup()
        {
            string save_data_path = automation_save_data_path;
            string save_picture_path = automation_save_picture_path;

            if (save_data_path == "")
            {
                richTextBox1.Text += "無 資料儲存路徑, 用預設值\n";
                //存csv的資料夾
                save_data_path = Application.StartupPath + "\\automation_csv";
            }

            if (save_picture_path == "")
            {
                richTextBox1.Text += "無 圖片儲存路徑, 用預設值\n";
                //存圖片的資料夾
                save_picture_path = Application.StartupPath + "\\automation_picture";
            }

            if (Directory.Exists(save_data_path) == false)
            {
                show_main_message1("資料儲存路徑 不存在", S_OK, 100);
                show_main_message2("資料儲存路徑 不存在", S_OK, 100);
            }
            else
            {
                show_main_message1("資料儲存路徑 OK", S_OK, 100);
                show_main_message2("資料儲存路徑 OK", S_OK, 100);
            }

            if (Directory.Exists(save_picture_path) == false)
            {
                show_main_message1("圖片儲存路徑 不存在", S_OK, 100);
                show_main_message2("圖片儲存路徑 不存在", S_OK, 100);
            }
            else
            {
                show_main_message1("圖片儲存路徑 OK", S_OK, 100);
                show_main_message2("圖片儲存路徑 OK", S_OK, 100);
            }

            //0: 色彩調教, 1: 資料燒錄
            int operation_mode = Properties.Settings.Default.operation_mode;
            if (operation_mode == 0)  //0: 色彩調教
            {
                richTextBox1.Text += "色彩調教\n";
                flag_automation_mode = MODE_AWB;
            }
            else if (operation_mode == 1)  //1: 資料燒錄
            {
                richTextBox1.Text += "資料燒錄\n";
                flag_automation_mode = MODE_WRITE_DATA;
            }
            else
            {
                richTextBox1.Text += "色彩調教\n";
                flag_automation_mode = MODE_AWB;
            }

            //是否使用真的PLC, true: 真上位PLC, false: 假上位, 偽裝PLC上位來下命令
            bool automation_use_plc = Properties.Settings.Default.automation_use_plc;
            if (automation_use_plc == true)
            {
                richTextBox1.Text += "真上位\n";
                flag_use_real_plc = true;
            }
            else
            {
                richTextBox1.Text += "假上位\n";
                flag_use_real_plc = false;
            }

            //是否使用真的 IMS 執行 燒錄 或 色調, true: 真下位, false: 假下位
            bool automation_use_ims = Properties.Settings.Default.automation_use_ims;
            if (automation_use_ims == true)
            {
                richTextBox1.Text += "真下位\n";
                flag_use_real_ims = true;
            }
            else
            {
                richTextBox1.Text += "假下位\n";
                flag_use_real_ims = false;
            }

            int egd_type = Properties.Settings.Default.egd_type;
            if (egd_type == 0)
            {
                richTextBox1.Text += "胃鏡\n";
                flag_use_esophagoscopy = false;   //胃鏡設定
            }
            else if (egd_type == 1)
            {
                richTextBox1.Text += "食道鏡\n";
                flag_use_esophagoscopy = true;   //食道鏡設定
            }
            else
            {
                richTextBox1.Text += "胃鏡\n";
                flag_use_esophagoscopy = false;   //胃鏡設定
            }

            int language = 0;
            if (language == 0)
            {
                richTextBox1.Text += "正體中文\n";
            }
            else if (language == 1)
            {
                richTextBox1.Text += "簡體中文\n";
            }
            else if (language == 2)
            {
                richTextBox1.Text += "英文\n";
            }
            else
            {
                richTextBox1.Text += "正體中文\n";
            }
        }

        void write_ims_type(int type)
        {
            string write_data1 = string.Empty;
            string write_data2 = string.Empty;
            string write_data3 = string.Empty;

            if (type == 0)
            {
                richTextBox1.Text += "設定主機為燒錄主機\n";
                write_data1 = "WRITE_DATA123";
                write_data2 = "WRITE_DATA123";
                write_data3 = "111111111111111111111111";
            }
            else
            {
                richTextBox1.Text += "設定主機為色調主機\n";
                write_data1 = "AWB__AWB__AWB";
                write_data2 = "AWB__AWB__AWB";
                write_data3 = "222222222222222222222222";
            }

            richTextBox1.Text += "資料1 : " + write_data1.Length.ToString() + "\n";
            richTextBox1.Text += "資料2 : " + write_data2.Length.ToString() + "\n";
            richTextBox1.Text += "資料3 : " + write_data3.Length.ToString() + "\n";

            if (get_comport_status() == false)
                return;

            string total_data = write_data1 + write_data2 + write_data3;
            richTextBox1.Text += "total_data len = " + total_data.Length.ToString() + "\n";

            byte[] main_board_model_data_send = new byte[50];

            int i;
            for (i = 0; i < main_board_model_data_send.Length; i++)
            {
                main_board_model_data_send[i] = 0;
            }
            for (i = 0; i < total_data.Length; i++)
            {
                main_board_model_data_send[i] = (byte)total_data[i];
            }

            Send_IMS_Data(0xF0, 0x12, 0x34, 0x56);   //main board model write

            serialPort2.Write(main_board_model_data_send, 0, main_board_model_data_send.Length);
            delay(200);
            delay(200);

            richTextBox1.Text += "寫入主機資料完成\n";
            return;
        }

