        private void timer_automation_Tick(object sender, EventArgs e)
        {

            return;

            //自動化專用timer, 一秒一個中斷
            //檢查 comport webcam 磁碟容量狀態....


            richTextBox1.Text += "A1 ";
            richTextBox_plc.Text += "A2 ";


            if ((DateTime.Now.Second % 5) == 2)
            {
                richTextBox1.Text += "每5秒檢查一次連線狀態\t" + DateTime.Now.ToString("yyyy/MM/dd HH:mm:ss") + "\t";

                timer_rtc_Tick(sender, e);
            }

            if ((DateTime.Now.Second % 10) == 0)
            {
                richTextBox1.Text += "每10秒檢查一次狀態\t" + DateTime.Now.ToString("yyyy/MM/dd HH:mm:ss") + "\t";

                richTextBox1.Text += timer_clock.Interval.ToString() + "\n";

                if (flag_camera_start == 1)
                {
                    if (check_ims_camera() == S_OK)
                    {
                        richTextBox1.Text += "111有InsightEyes影像裝置\n";
                    }
                    else
                    {
                        richTextBox1.Text += "111無InsightEyes影像裝置\n";

                        if (Cam != null)
                        {
                            richTextBox1.Text += "1111\n";
                            if ((flag_camera_start == 1) && (Cam.IsRunning == true))
                            {
                                richTextBox1.Text += "USB影像傳輸中, 關閉\n";
                                flag_camera_start = 0;
                                Stop_Webcam();
                                comboBox_webcam.Items.Clear();
                            }
                            else
                            {
                                richTextBox1.Text += "2222\n";

                                Cam.Stop();  // WebCam stops capturing images.
                                Cam.SignalToStop();
                                Cam.WaitForStop();
                                while (Cam.IsRunning)
                                {
                                }
                                Cam = null;
                            }
                        }

                        richTextBox1.Text += "3333\n";

                        if (Cam != null)
                        {
                            richTextBox1.Text += "4444\n";
                            if (Cam.IsRunning == true)  // When Form1 closes itself, WebCam must stop, too.
                            {
                                flag_camera_start = 0;
                                Stop_Webcam();
                                richTextBox1.Text += "先關閉camera\n";
                            }
                        }
                        else
                        {
                            richTextBox1.Text += "camera is null\n";
                        }
                        flag_camera_start = 0;
                        richTextBox1.Text += "5555\n";
                    }
                }
                else
                {
                    if (check_ims_camera() == S_OK)
                    {
                        richTextBox1.Text += "000有InsightEyes影像裝置\n";
                        if ((flag_operation_mode == MODE_RELEASE_STAGE0) || (flag_operation_mode == MODE_RELEASE_STAGE2)
                            || (flag_operation_mode == MODE_RELEASE_STAGE1A) || (flag_operation_mode == MODE_RELEASE_STAGE1B) || (flag_operation_mode == MODE_RELEASE_STAGE3))
                        {
                            richTextBox1.Text += "call Init_WebcamSetup() 333\n";
                            Init_WebcamSetup();
                        }

                    }
                    else
                    {
                        richTextBox1.Text += "000無InsightEyes影像裝置\n";
                    }
                }
            }
        }

