        void WriteToSerialPort2(byte[] data, int offset, int count)
        {
            //serialPort2.Write(data, offset, count);
            try
            {   //可能會產生錯誤的程式區段
                serialPort2.Write(data, offset, count);
            }
            catch (Exception ex)
            {   //定義產生錯誤時的例外處理程式碼
                richTextBox1.Text += "xxx錯誤訊息e02a : " + ex.Message + "\n";
            }
            finally
            {
                //一定會被執行的程式區段
            }
        }

        private void timer_connection_status_Tick(object sender, EventArgs e)
        {
            if ((flag_operation_mode == MODE_RELEASE_STAGE0) || (flag_operation_mode == MODE_RELEASE_STAGE2))
            {
                //richTextBox_plc.Text += "更新 通 連 相 影\n";
                //pbx_ims_connection1.BackgroundImage = Properties.Resources.ims_connection1_OFF;
                //pbx_ims_connection2.BackgroundImage = Properties.Resources.ims_connection2_OFF;
                //bx_ims_connection3.BackgroundImage = Properties.Resources.ims_connection3_OFF;

                //通信 comport
                flag_wait_receive_data = 1;
                if (flag_enaglb_automation == false)
                {
                    //一般使用
                    Send_IMS_Data0(0xFF, 0x11, 0x52, 0x00); //directly send uart command
                }
                else
                {
                    //自動化製程使用
                    if (flag_automation_mode == MODE_AWB)   //自動化製程 + 色調
                    {
                        Send_IMS_Data0(0xFF, 0x11, 0x52, 0xAB); //directly send uart command
                    }
                    else if (flag_automation_mode == MODE_WRITE_DATA)   //自動化製程 + 燒錄
                    {
                        Send_IMS_Data0(0xFF, 0x11, 0x52, 0xCD); //directly send uart command
                    }
                    else
                    {
                        Send_IMS_Data0(0xFF, 0x11, 0x52, 0x00); //directly send uart command
                    }
                }
                int cnt = 0;
                while ((flag_wait_receive_data == 1) && (cnt++ < 60))
                {
                    //richTextBox_plc.Text += "x";
                    delay(10);
                }

                flag_wait_receive_data = 0;
                //richTextBox_plc.Text += "cnt1 = " + cnt.ToString() + "\n";    //usually cnt = 4

                //連接器 相機
                Send_IMS_Data(0xFF, 0, 0, 0);
                cnt = 0;
                while ((flag_wait_receive_data == 1) && (cnt++ < 60))
                {
                    //richTextBox_plc.Text += "+";
                    delay(10);
                }
                flag_wait_receive_data = 0;
                //richTextBox_plc.Text += "cnt2 = " + cnt.ToString() + "\n";    //usually cnt = 4

                //影像

            }
        }

