        void show_awb_data(bool en)
        {
            if (en == true)
            {
                flag_show_awb_info = true;

                pictureBox2.Visible = true;
                groupBox_temperature.Visible = true;
                groupBox_awb2.Visible = true;
                groupBox_sn1.Visible = true;
                groupBox_wpt_bpt.Visible = true;
                panel_camera_status6.Visible = true;
            }
            else
            {
                flag_show_awb_info = false;

                pictureBox2.Visible = false;
                groupBox_temperature.Visible = false;
                groupBox_awb2.Visible = false;
                groupBox_sn1.Visible = false;
                groupBox_wpt_bpt.Visible = false;
                panel_camera_status6.Visible = false;
            }
        }

        private void cb_show_image_info_CheckedChanged(object sender, EventArgs e)
        {
            if (cb_show_image_info.Checked == true)
            {
                cb_show_info.Checked = true;
                cb_show_image_info.Checked = true;
                show_awb_data(true);

                groupBox_awb2.Visible = true;
                groupBox_sn1.Visible = true;
                groupBox_wpt_bpt.Visible = true;
                lb_yuv_y2.Location = new Point(1610 + 35, 740 + 45);
                cb_Contrast_Brightness_Gamma.Visible = true;
                cb_Gamma.Visible = true;
                panel_camera_status6.Visible = true;
            }
            else
            {
                cb_show_info.Checked = false;
                cb_show_image_info.Checked = false;
                show_awb_data(false);

                groupBox_awb2.Visible = false;
                groupBox_wpt_bpt.Visible = false;
                lb_yuv_y2.Location = new Point(1795, 12);
                cb_Contrast_Brightness_Gamma.Visible = false;
                cb_Gamma.Visible = false;
                panel_camera_status6.Visible = false;
            }
        }

        private void cb_auto_CheckedChanged(object sender, EventArgs e)
        {
