                lb_bpt2.Visible = true;
            }
        }

        int do_rework(object sender, EventArgs e)
        {
            richTextBox1.Text += "開始重工\n";
            bt_rework_status.Text = "開始重工1";

            bt_rework.BackColor = Color.Red;

            numericUpDown_brightness.Value = 90;    //食道鏡設定

            string mesg = string.Empty;

            if (get_comport_status() == false)
            {
                richTextBox1.Text += "無 Comport\n";
                bt_rework_status.Text = "無 Comport";
                return S_FALSE;
            }

            g_conn_status = get_camera_status();

            if (g_conn_status != CAMERA_OK)
            {
                richTextBox1.Text += "無 相機\n";
                bt_rework_status.Text = "無 相機";
                return S_FALSE;
            }

            global_rework_time = 0;
            timer_rework1.Enabled = true;
            lb_rework_time.Visible = true;

            //reset資料
            global_data_r = 0;
            global_data_b = 0;
            global_data_r_old = 0;
            global_data_b_old = 0;
            tb_info_aa1.Text = "";
            tb_info_aa2.Text = "";

            richTextBox1.Text += "讀取資料\n";
            bt_rework_status.Text = "讀取資料2";
            bt_camera_info_read_Click(sender, e);

            richTextBox1.Text += "------------------------------------------------------------\n";  // 60個

            /*
            //debug
            tb_info_aa1.Text = "EC05280190";
            tb_info_aa2.Text = "N21110010065";
            global_data_r = 1379;
            global_data_b = 1632;
            */
            richTextBox1.Text += "準備燒錄\n";
            bt_rework_status.Text = "準備燒錄3";

            if ((tb_info_aa1.Text.Length > 5) && (tb_info_aa2.Text.Length > 5))
            {
                richTextBox1.Text += "取得 SN1 : " + tb_info_aa1.Text + "\n";
                richTextBox1.Text += "取得 SN2 : " + tb_info_aa2.Text + "\n";
            }
            else
            {
                richTextBox1.Text += "未取得相機序號\n";
                bt_rework_status.Text = "無 相機序號";
                timer_rework1.Enabled = false;
                return S_FALSE;
            }

            if ((global_data_r > 100) && (global_data_b > 100))
            {
                richTextBox1.Text += "取得 AWB R : " + global_data_r.ToString() + "\n";
                richTextBox1.Text += "取得 AWB B : " + global_data_b.ToString() + "\n";
            }
            else
            {
                richTextBox1.Text += "未取得AWB參數1\n";
                bt_rework_status.Text = "無 AWB參數1";
                timer_rework1.Enabled = false;
                return S_FALSE;
            }

            richTextBox1.Text += "------------------------------------------------------------\n";  // 60個

            richTextBox1.Text += "清除相機資料\n";
            bt_rework_status.Text = "清除相機資料4";

            erase_camera_data();
            delay(500);//1秒
            delay(500);//1秒
            delay(500);//1秒
            delay(500);//1秒

            richTextBox1.Text += "------------------------------------------------------------\n";  // 60個

            richTextBox1.Text += "保存參數相機序號\n";
            string sn1_old = tb_info_aa1.Text;
            string sn2_old = tb_info_aa2.Text;
            richTextBox1.Text += "保存參數AWB\n";
            global_data_r_old = global_data_r;
            global_data_b_old = global_data_b;

            richTextBox1.Text += "------------------------------------------------------------\n";  // 60個

            richTextBox1.Text += "燒錄相機序號\n";
            bt_rework_status.Text = "燒錄相機序號5";

            richTextBox1.Text += "取得 SN1 : " + tb_info_aa1.Text + "\n";
            richTextBox1.Text += "取得 SN2 : " + tb_info_aa2.Text + "\n";

            tb_sn1.Text = tb_info_aa1.Text;
            tb_sn2.Text = tb_info_aa2.Text;

            richTextBox1.Text += "相機序號1長度 : " + tb_sn1.Text.Length.ToString() + "\n";
            richTextBox1.Text += "相機序號2長度 : " + tb_sn2.Text.Length.ToString() + "\n";

            button11_Click(sender, e);//執行燒錄按鍵

            delay(500);//1秒
            delay(500);//1秒
            delay(500);//1秒
            delay(500);//1秒

            richTextBox1.Text += "------------------------------------------------------------\n";  // 60個

            bool flag_rework_error = false;

            ims_read_camera_serial();//讀取相機序號

            if ((tb_info_aa1.Text.Length > 5) && (tb_info_aa2.Text.Length > 5))
            {
                richTextBox1.Text += "取得 SN1 : " + tb_info_aa1.Text + "\n";
                richTextBox1.Text += "取得 SN2 : " + tb_info_aa2.Text + "\n";
            }
            else
            {
                richTextBox1.Text += "未取得相機序號\n";
                bt_rework_status.Text = "無 相機序號";

                //再讀一次
                ims_read_camera_serial();//讀取相機序號
                if ((tb_info_aa1.Text.Length > 5) && (tb_info_aa2.Text.Length > 5))
                {
                    richTextBox1.Text += "取得 SN1 : " + tb_info_aa1.Text + "\n";
                    richTextBox1.Text += "取得 SN2 : " + tb_info_aa2.Text + "\n";
                }
                else
                {
                    richTextBox1.Text += "未取得相機序號\n";
                    bt_rework_status.Text = "無 相機序號";

                    //再讀一次
                    ims_read_camera_serial();//讀取相機序號
                    if ((tb_info_aa1.Text.Length > 5) && (tb_info_aa2.Text.Length > 5))
                    {
                        richTextBox1.Text += "取得 SN1 : " + tb_info_aa1.Text + "\n";
                        richTextBox1.Text += "取得 SN2 : " + tb_info_aa2.Text + "\n";
                    }
                    else
                    {
                        richTextBox1.Text += "未取得相機序號\n";
                        bt_rework_status.Text = "無 相機序號";
                        flag_rework_error = true;
                    }
                }
            }

            if (sn1_old != tb_info_aa1.Text)
            {
                richTextBox1.Text += "錯誤1\n";
                flag_rework_error = true;
            }

            if (sn2_old != tb_info_aa2.Text)
            {
                richTextBox1.Text += "錯誤2\n";
                flag_rework_error = true;
            }

            richTextBox1.Text += "------------------------------------------------------------\n";  // 60個

            richTextBox1.Text += "燒錄AWB參數\n";
            bt_rework_status.Text = "燒錄AWB參數6";

            richTextBox1.Text += "取得 AWB R : " + global_data_r.ToString() + "\n";
            richTextBox1.Text += "取得 AWB B : " + global_data_b.ToString() + "\n";

            //new method, write to AWB_PAGE1
            int i;
            int page = AWB_PAGE1;
            for (i = 0; i < 16; i++)
            {
                user_flash_data[i] = 0;
            }

            //ex: DA-52-1A-04-52-1B-D2-52-1E-07-52-1F-08-00-00-00

            user_flash_data[0] = 0xDA;  //header

            user_flash_data[1] = 0x52;  //AWB R H AH
            user_flash_data[2] = 0x1A;  //AWB R H AL
            user_flash_data[3] = (Byte)(global_data_r / 256);

            user_flash_data[4] = 0x52;  //AWB R L AH
            user_flash_data[5] = 0x1B;  //AWB R L AL
            user_flash_data[6] = (Byte)(global_data_r % 256);

            user_flash_data[7] = 0x52;  //AWB B H AH
            user_flash_data[8] = 0x1E;  //AWB B H AL
            user_flash_data[9] = (Byte)(global_data_b / 256);

            user_flash_data[10] = 0x52; //AWB B L AH
            user_flash_data[11] = 0x1F; //AWB B L AL
            user_flash_data[12] = (Byte)(global_data_b % 256);

            user_flash_data[13] = 0x00; //dummy, no data
            user_flash_data[14] = 0x00; //dummy, no data
            user_flash_data[15] = 0x00; //dummy, no data

            Send_IMS_Data(0xD0, (byte)page, 0, 0);  //write user data to camera flash
            serialPort2.Write(user_flash_data, 0, 16);

            richTextBox1.Text += "------------------------------------------------------------\n";  // 60個
            delay(500);//1秒

            ims_read_camera_awb();//讀取AWB參數

            if ((global_data_r > 100) && (global_data_b > 100))
            {
                richTextBox1.Text += "取得 AWB R : " + global_data_r.ToString() + "\n";
                richTextBox1.Text += "取得 AWB B : " + global_data_b.ToString() + "\n";
            }
            else
            {
                richTextBox1.Text += "未取得AWB參數2\n";
                bt_rework_status.Text = "無 AWB參數2";

                ims_read_camera_awb();//讀取AWB參數

                if ((global_data_r > 100) && (global_data_b > 100))
                {
                    richTextBox1.Text += "取得 AWB R : " + global_data_r.ToString() + "\n";
                    richTextBox1.Text += "取得 AWB B : " + global_data_b.ToString() + "\n";
                }
                else
                {
                    richTextBox1.Text += "未取得AWB參數2\n";
                    bt_rework_status.Text = "無 AWB參數2";


                    if ((global_data_r > 100) && (global_data_b > 100))
                    {
                        richTextBox1.Text += "取得 AWB R : " + global_data_r.ToString() + "\n";
                        richTextBox1.Text += "取得 AWB B : " + global_data_b.ToString() + "\n";
                    }
                    else
                    {
                        richTextBox1.Text += "未取得AWB參數2\n";
                        bt_rework_status.Text = "無 AWB參數2";
                        flag_rework_error = true;
                    }
                }
            }

            if (global_data_r != global_data_r_old)
            {
                richTextBox1.Text += "錯誤3\n";
                flag_rework_error = true;
            }
            if (global_data_b != global_data_b_old)
            {
                richTextBox1.Text += "錯誤4\n";
                flag_rework_error = true;
            }

            richTextBox1.Text += "------------------------------------------------------------\n";  // 60個

            delay(500);//1秒
            delay(500);//1秒
            delay(500);//1秒
            delay(500);//1秒

            richTextBox1.Text += "燒錄其他參數\n";
            bt_rework_status.Text = "燒錄其他參數7";
            do_save_camera_data();  //write saturation brightness data

            richTextBox1.Text += "------------------------------------------------------------\n";  // 60個

            delay(500);//1秒

            ims_read_camera_brightness();//讀取相機亮度中值
            richTextBox1.Text += "取得 亮度中值 : " + global_user_brigheness.ToString() + "\n";

            if (global_user_brigheness != 90)
            {
                richTextBox1.Text += "未取得亮度中值\n";

                //再讀一次
                ims_read_camera_brightness();//讀取相機亮度中值
                richTextBox1.Text += "取得 亮度中值 : " + global_user_brigheness.ToString() + "\n";

                if (global_user_brigheness != 90)
                {
                    richTextBox1.Text += "未取得亮度中值\n";

                    //再讀一次
                    ims_read_camera_brightness();//讀取相機亮度中值
                    richTextBox1.Text += "取得 亮度中值 : " + global_user_brigheness.ToString() + "\n";

                    if (global_user_brigheness != 90)
                    {
                        richTextBox1.Text += "未取得亮度中值\n";

                        //再寫一次
                        delay(500);//1秒
                        delay(500);//1秒
                        richTextBox1.Text += "燒錄其他參數\n";
                        bt_rework_status.Text = "燒錄其他參數";
                        do_save_camera_data();  //write saturation brightness data
                        delay(500);//1秒
                        delay(500);//1秒

                        //再讀一次
                        ims_read_camera_brightness();//讀取相機亮度中值
                        richTextBox1.Text += "取得 亮度中值 : " + global_user_brigheness.ToString() + "\n";

                        if (global_user_brigheness != 90)
                        {
                            richTextBox1.Text += "未取得亮度中值\n";

                            //再讀一次
                            ims_read_camera_brightness();//讀取相機亮度中值
                            richTextBox1.Text += "取得 亮度中值 : " + global_user_brigheness.ToString() + "\n";
                            if (global_user_brigheness != 90)
                            {

                                richTextBox1.Text += "未取得亮度中值\n";
                                richTextBox1.Text += "錯誤5\n";
                                flag_rework_error = true;
                            }
                        }
                    }
                }
            }

            richTextBox1.Text += "------------------------------------------------------------\n";  // 60個

            richTextBox1.Text += "作業完成\n";
            bt_rework_status.Text = "作業完成";

            bt_rework.BackColor = SystemColors.ControlLight;

            timer_rework1.Enabled = false;

            if (flag_rework_error == true)
            {
                bt_rework_status.Text = "驗證錯誤";
                return S_FALSE;
            }
            else
            {
                bt_rework_status.Text = "驗證成功\n重工完成";
                return S_OK;
            }
        }

        //讀取相機序號
        void ims_read_camera_serial()
        {
            tb_info_aa1.BackColor = Color.White;
            tb_info_aa1.Clear();
            tb_info_aa2.BackColor = Color.White;
            tb_info_aa2.Clear();

            richTextBox1.Text += "讀取 相機序號\n";
            for (int count = 0; count < 5; count++)
            {
                tb_info_aa1.Text = "";
                tb_info_aa2.Text = "";

                Get_IMS_Data(0, 0xAA, 0xAA);
                int cnt = 0;
                while ((flag_wait_receive_data == 1) && (cnt++ < 20))
                {
                    richTextBox1.Text += "+";
                    delay(100);
                }
                flag_wait_receive_data = 0;

                if ((tb_info_aa1.Text.Length > 5) && (tb_info_aa2.Text.Length > 5))
                {
                    richTextBox1.Text += "取得 SN1 : " + tb_info_aa1.Text + "\n";
                    richTextBox1.Text += "取得 SN2 : " + tb_info_aa2.Text + "\n";
                    richTextBox1.Text += "共讀取 " + (count + 1).ToString() + " 次\n";
                    break;
                }
            }
        }

        //讀取AWB參數
        void ims_read_camera_awb()
        {
            for (int count = 0; count < 5; count++)
            {
                global_data_r = 0;
                global_data_b = 0;
                flag_read_camera_raw_data = 1;
                richTextBox1.Text += "讀取 AWB_PAGE1\n";
                flag_wait_receive_data = 1;
                byte page = AWB_PAGE1;
                Send_IMS_Data(0xD1, (byte)page, 0, 0);
                int cnt = 0;
                while ((flag_wait_receive_data == 1) && (cnt++ < 20))
                {
                    richTextBox1.Text += "+";
                    delay(100);
                }
                flag_wait_receive_data = 0;

                if ((global_data_r > 100) && (global_data_b > 100))
                {
                    richTextBox1.Text += "取得 AWB R : " + global_data_r.ToString() + "\n";
                    richTextBox1.Text += "取得 AWB B : " + global_data_b.ToString() + "\n";
                    richTextBox1.Text += "共讀取 " + (count + 1).ToString() + " 次\n";
                    break;
                }
            }
        }

        //讀取相機亮度中值
        void ims_read_camera_brightness()
        {
            richTextBox1.Text += "讀取 相機亮度中值\n";
            for (int count = 0; count < 5; count++)
            {
                global_user_brigheness = 0;

                //page = (byte)USER_PAGE2;
                Get_IMS_Data(1, USER_PAGE2, 0xAA);

                int cnt = 0;
                while ((flag_wait_receive_data == 1) && (cnt++ < 20))
                {
                    richTextBox1.Text += "+";
                    delay(100);
                }
                flag_wait_receive_data = 0;

                if (global_user_brigheness > 50)
                {
                    richTextBox1.Text += "取得 亮度中值 : " + global_user_brigheness.ToString() + "\n";
                    break;
                }
            }
        }

        private void bt_rework_Click(object sender, EventArgs e)
        {
            int result = do_rework(sender, e);
            if (result == S_OK)
            {
                richTextBox1.Text += "重工成功\n";
            }
            else
            {
                richTextBox1.Text += "重工失敗\n";
            }
        }

        int global_rework_test_ok = 0;
        int global_rework_test_ng = 0;
        private void bt_rework_test_Click(object sender, EventArgs e)
        {
            global_rework_test_ok = 0;
            global_rework_test_ng = 0;
            for (int global_rework_test_cnt = 1; global_rework_test_cnt < 1000; global_rework_test_cnt++)
            {
                richTextBox1.Text += "第 " + global_rework_test_cnt.ToString() + " 次重工測試, 時間 : " + DateTime.Now.ToString() + "\n";
                int result = do_rework(sender, e);
                if (result == S_OK)
                {
                    richTextBox1.Text += "第 " + global_rework_test_cnt.ToString() + " 次重工測試, 成功, 時間 : " + DateTime.Now.ToString() + "\n";
                    global_rework_test_ok++;
                }
                else
                {
                    richTextBox1.Text += "第 " + global_rework_test_cnt.ToString() + " 次重工測試, 失敗, 時間 : " + DateTime.Now.ToString() + "\n";
                    global_rework_test_ng++;
                }
                bt_rework_test.Text = "重工測試\n" + global_rework_test_ok.ToString() + "/" + global_rework_test_ng.ToString();
            }
        }

        private void timer_rework1_Tick(object sender, EventArgs e)
        {
            global_rework_time++;
            lb_rework_time.Text = global_rework_time.ToString() + "/40";
        }
    }
